import { G, T, A, O, P } from './domains.js';

export const part4 = [
  {id:379,domain:G,question:"What is the purpose of certificate transparency (CT) logs?",options:["Encrypting all certificate metadata before it is transmitted between certificate authorities and clients","A public, append-only log where CAs record issued certificates, enabling detection of misissued certificates","Archiving expired certificates in a separate long-term repository purely for historical auditing purposes","Distributing real-time certificate revocation status information to browsers and relying parties"],answer:1,explanation:"CT logs allow domain owners and browsers to detect unauthorized certificates issued for their domains (catching rogue CAs and certificate abuse).",optionExplanations:["CT logs make certificate issuance public and auditable rather than encrypted; they do not encrypt certificate data at all.","Certificate transparency requires CAs to log every certificate to public, tamper-evident logs, allowing anyone to monitor for unauthorized certificates for their domains.","Expired certificate archival is a different long-term storage concern; CT logs instead focus on documenting all newly issued certificates as they are created.","CRL and OCSP are the mechanisms that distribute revocation information; CT logs instead document the existence of issued certificates for public monitoring."]},
  {id:380,domain:T,question:"What is a supply chain attack?",options:["Physically stealing goods or equipment directly from a company's storage warehouse","Compromising a target by attacking a less-secure element of their supply chain, such as a vendor","Launching the identical piece of malware simultaneously against many unrelated targets at once","Deploying ransomware directly against a company's own shipping and logistics management systems"],answer:1,explanation:"Supply chain attacks like SolarWinds compromise trusted software/hardware that targets install, achieving broad access via a trusted channel.",optionExplanations:["Physical warehouse theft is a physical security incident involving stolen goods; supply chain attacks instead compromise digital elements of the supply chain.","Supply chain attacks insert malware into trusted software updates, compromise hardware at manufacturing, or pivot through trusted managed service providers to reach the ultimate target.","Attacking many unrelated targets with the same malware describes a broad campaign; supply chain attacks specifically exploit trust between a vendor and its customers.","Ransomware against logistics systems is a direct attack on that target; supply chain attacks instead use a compromised vendor relationship to reach a higher-value target."]},
  {id:381,domain:A,question:"What is containerization from a security perspective?",options:["Physically isolating hardware servers from one another within separate locked data center cages","Packaging applications with dependencies in containers that share an OS kernel, secured via namespace isolation","Encrypting application data both at rest and in transit using standard cryptographic algorithms","Deploying each application inside its own fully virtualized machine with a dedicated guest operating system"],answer:1,explanation:"Container security relies on kernel namespace isolation, but containers share the host kernel — a kernel exploit can escape all containers on that host.",optionExplanations:["Physical server isolation is hardware-level separation using distinct physical machines; containerization is instead OS-level isolation running on shared hardware.","Containers use Linux namespaces (process, network, mount) and cgroups to isolate applications, but share the host kernel, making kernel security critical.","Data encryption is a separate confidentiality control applied independently; containerization is instead about isolating applications and controlling their shared resources.","VMs virtualize hardware to provide full separate guest operating systems; containers instead share the host OS kernel, offering lighter but less complete isolation."]},
  {id:382,domain:P,question:"What is data sovereignty?",options:["Legally owning the intellectual property rights associated with a company's proprietary data","The principle that data is subject to the laws and governance of the country where it is physically stored or processed","The legal claim that a government directly owns all personal data belonging to its citizens","Encrypting sensitive data exclusively using cryptographic algorithms formally approved by a national government"],answer:1,explanation:"Data sovereignty concerns arise when organizations store data in foreign countries where local laws may compel disclosure without the data owner's consent.",optionExplanations:["Intellectual property ownership is a separate legal concept from data sovereignty; sovereignty instead concerns which government's laws govern the data's storage.","Data sovereignty means data stored in Country A is subject to Country A's laws — including government access laws — regardless of where the data owner is located.","Direct government ownership of citizen data is not what data sovereignty means; sovereignty is instead about legal jurisdiction over where data resides.","Using nationally approved encryption algorithms is a specific compliance requirement in some jurisdictions; sovereignty instead concerns geographic jurisdiction and which laws apply."]},
  {id:383,domain:O,question:"What is the purpose of a security operations center (SOC)?",options:["Developing detailed software security requirements during the early design phase of a project","A centralized team and facility dedicated to continuously monitoring, detecting, and responding to threats","Performing formal, comprehensive security audits on an annual or otherwise periodic basis","Managing overall IT infrastructure performance, uptime, and capacity across the organization"],answer:1,explanation:"SOCs provide 24/7 monitoring, alert triage, threat hunting, and incident response coordination to maintain organizational security posture.",optionExplanations:["Software security requirements are defined as part of secure development programs; a SOC instead focuses on continuous operational monitoring and response.","A SOC centralizes security monitoring tools (SIEM, EDR), analysts, and processes to provide continuous detection and response capabilities.","Annual audits are periodic point-in-time compliance activities; a SOC instead provides continuous, ongoing, around-the-clock security operations.","IT infrastructure performance is typically managed by a Network Operations Center (NOC); a SOC instead focuses specifically on security threats and incidents."]},
  {id:384,domain:T,question:"What is DNS poisoning (DNS cache poisoning)?",options:["Overwhelming a DNS server with an excessive flood of simultaneous lookup requests","Inserting fraudulent DNS records into a resolver's cache to redirect users to malicious servers","Permanently deleting the legitimate DNS records associated with a specific domain name","Encrypting DNS query traffic end-to-end to prevent third parties from eavesdropping"],answer:1,explanation:"DNS poisoning redirects traffic by corrupting cached DNS responses, sending users to attacker-controlled IPs while they believe they're visiting legitimate sites.",optionExplanations:["Overloading a DNS server with requests describes a DNS-targeted DDoS attack; poisoning instead corrupts the cached records themselves rather than causing unavailability.","DNS cache poisoning inserts malicious DNS entries that redirect users to attacker-controlled servers — enabling credential theft, malware distribution, or man-in-the-middle attacks.","Deleting DNS records causes service unavailability for that domain; poisoning instead redirects traffic to malicious destinations rather than removing records.","DNS encryption protocols like DoH and DoT are a defense against interception; poisoning instead attacks the integrity of the cached records themselves."]},
  {id:385,domain:G,question:"What is the principle of non-repudiation?",options:["The administrative ability to permanently delete transaction records from a system's audit log","The assurance that a party cannot deny having performed an action or sent a message","Ensuring that all parties to a transaction remain completely anonymous and untraceable","Preventing any unauthorized party from gaining access to sensitive stored records"],answer:1,explanation:"Non-repudiation (achieved through digital signatures and audit logs) ensures entities cannot deny actions — essential for legal accountability and forensics.",optionExplanations:["Deleting transaction records would actually undermine non-repudiation; the principle instead ensures records cannot be disavowed or denied.","Non-repudiation ensures the originator of a message or performer of an action cannot credibly deny it — digital signatures cryptographically bind identity to actions.","Anonymity directly contradicts non-repudiation, since the principle requires traceable, verifiable identity, not the ability to remain unidentified.","Preventing unauthorized access describes the confidentiality and access control goals; non-repudiation instead ensures authorized users cannot disavow their own legitimate actions."]},
  {id:386,domain:A,question:"What is a reverse proxy and how does it improve security?",options:["A specialized firewall configured specifically to block unwanted outbound traffic leaving the network","A server sitting in front of web servers, forwarding requests while hiding backend identity and applying controls","A dedicated VPN server that establishes encrypted tunnels for remote employees connecting into the office","A caching proxy positioned to store frequently requested web content purely to improve performance"],answer:1,explanation:"Reverse proxies hide server architecture, terminate SSL, apply WAF rules, provide DDoS protection, and load balance — all in a security-controlled layer.",optionExplanations:["Outbound traffic blocking is typically handled by forward proxies and egress firewalls; reverse proxies instead handle inbound traffic to protected web servers.","A reverse proxy receives client requests, applies security inspection, and forwards to appropriate backend servers — clients never directly communicate with backend servers.","VPNs provide encrypted tunnels for remote user connectivity; reverse proxies instead control and inspect access to web services from external users.","Forward proxies primarily cache content to improve outbound browsing performance; reverse proxies can cache too, but they primarily provide security and request routing."]},
  {id:387,domain:O,question:"What is digital forensics chain of custody?",options:["A specialized forensic technique used to recover deleted or intentionally hidden files from storage media","The documented, unbroken record of who has possessed and accessed evidence from collection through trial","A cryptographic method investigators use specifically to decrypt data stored on seized devices","A formal process for promptly notifying law enforcement agencies once a cybercrime is discovered"],answer:1,explanation:"Chain of custody ensures evidence is admissible in court by proving it was not tampered with and was handled by accountable, documented individuals.",optionExplanations:["File recovery is a specific forensic examination technique; chain of custody is instead the documentation process surrounding how evidence is handled.","Chain of custody tracks every transfer of evidence — who collected it, when, where it was stored, who accessed it — creating an auditable record proving evidence integrity.","Device decryption is a technical forensic examination step performed on evidence; chain of custody is instead the overarching documentation framework for all evidence handling.","Law enforcement notification is an incident response activity that may occur separately; chain of custody is instead the evidence integrity framework applied once evidence is collected."]},
  {id:388,domain:T,question:"What is a man-in-the-browser (MiTB) attack?",options:["A physical hardware attack that targets the servers hosting browser infrastructure and services","Malware that intercepts and modifies browser transactions in real time before encryption, evading SSL","Passively stealing a user's stored browser history along with any saved autofill passwords","Injecting unwanted advertisements directly into legitimate web pages that a user is browsing"],answer:1,explanation:"MiTB malware sits inside the browser, modifying transactions (like changing bank transfer amounts) after the user initiates them but before encryption.",optionExplanations:["Physical attacks on browser infrastructure describe hardware-level intrusion, not what MiTB describes; it is instead a malware category operating inside the browser process itself.","MiTB malware (like Zeus/SpyEye) hooks into browser APIs to intercept and modify content that users see and transactions they submit, defeating HTTPS because modification happens before encryption.","Stealing saved credentials and history is a function of keyloggers and password-stealing malware; MiTB instead actively modifies live browser transactions in real time.","Ad injection is characteristic of adware; MiTB is instead specifically designed to manipulate financial and other sensitive transactions in real time."]},
  {id:389,domain:P,question:"What is the purpose of an acceptable use policy (AUP)?",options:["Describing the technical layout and architecture of an organization's network infrastructure","Defining what actions are permitted and prohibited when using organizational technology resources","Setting formal coding and software development standards for engineering teams","Outlining the physical security requirements for securing office facilities and equipment"],answer:1,explanation:"AUPs set clear expectations for technology use, provide legal basis for disciplinary action, and help establish reasonable personal use boundaries.",optionExplanations:["Network architecture is documented in technical network diagrams; an AUP instead governs acceptable behavior when using those networks and systems.","An AUP defines permitted activities (work-related internet use) and prohibited ones (downloading pirated software, accessing inappropriate content) on organizational systems and networks.","Software development standards are defined in secure coding guidelines; an AUP instead covers the broader acceptable use of technology resources by all users.","Physical security requirements are documented in physical security policies; an AUP instead focuses on the appropriate use of IT resources and systems."]},
  {id:390,domain:G,question:"What is the difference between hashing and encryption?",options:["Hashing and encryption are actually the same underlying cryptographic process, just called by different names","Hashing is a one-way function producing a fixed-length digest; encryption is reversible with the appropriate key","Encryption algorithms are inherently faster than hashing algorithms across every possible use case","Hashing always requires a secret key for its computation, while encryption never uses keys at all"],answer:1,explanation:"Hashing cannot be reversed to retrieve the original data — it's for integrity verification, not confidentiality. Encryption can be reversed with the key.",optionExplanations:["Hashing and encryption are fundamentally different operations that serve entirely different security goals, not interchangeable names for the same process.","Hashing is one-way (you cannot recover the original input); encryption is two-way (decryption with the key recovers the original). Hashing serves integrity; encryption serves confidentiality.","Hash functions like SHA-256 are generally very fast, and encryption speed varies by algorithm and key size — there is no universal speed advantage either way.","This is backwards — symmetric and asymmetric encryption require keys, while standard hashing uses no key at all (though HMAC does add one)."]},
  {id:391,domain:T,question:"What is a fileless malware attack?",options:["Malware that conceals its malicious payload inside the pixel data of ordinary image files","Malware that operates entirely in memory using legitimate tools, leaving no persistent files on disk","Malware specifically crafted to exploit vulnerabilities in PDF document readers and viewers","Malware that encrypts a victim's files for extortion while leaving the originals intact"],answer:1,explanation:"Fileless malware (using PowerShell, WMI, registry) is difficult to detect with traditional AV since it never writes files to disk that can be scanned.",optionExplanations:["Malware hiding inside image files uses steganographic techniques; fileless malware instead specifically avoids writing any files to disk at all.","Fileless malware resides entirely in RAM, uses built-in tools like PowerShell, and persists through registry keys or scheduled tasks — never writing traditional executable files.","PDF-targeting exploits are a delivery mechanism that may drop malware; fileless techniques instead describe how malware operates after the initial delivery has occurred.","File-encrypting malware that withholds deletion describes a form of ransomware; fileless malware instead describes staying memory-resident without leaving disk artifacts."]},
  {id:392,domain:A,question:"What is a DMZ (demilitarized zone) in network security?",options:["A restricted network region where absolutely no traffic or network activity is ever permitted","A network segment between the internet and internal network that hosts public-facing services","A dedicated network zone set aside exclusively for managing wireless access points","A dedicated network area reserved exclusively for hosting security monitoring and logging tools"],answer:1,explanation:"DMZs host web servers, mail servers, and DNS servers that need internet exposure while the firewall prevents direct internet access to internal systems.",optionExplanations:["A zone with no network activity at all does not describe a DMZ; it is instead an active network zone with carefully defined connectivity rules.","A DMZ is flanked by two firewalls — one controlling internet traffic to the DMZ, another controlling DMZ traffic to the internal network, providing layered protection.","A zone reserved solely for wireless access points is not the DMZ concept; a DMZ instead hosts public-facing services isolated from the internal network.","Security tools typically reside in a separate management network; the DMZ instead hosts services that specifically need to be publicly accessible from the internet."]},
  {id:393,domain:O,question:"What is the purpose of a honeypot in network security?",options:["A facility dedicated to collecting honey bees to support the organization's sustainability initiatives","A decoy system designed to attract and detect attackers, gathering intelligence on their techniques","A centralized database used for securely storing and managing digital security certificates","Actively blocking malicious traffic before it ever reaches the network perimeter defenses"],answer:1,explanation:"Honeypots distract attackers, provide intelligence on TTPs, trigger alerts when accessed (since no legitimate user should access them), and slow down attacks.",optionExplanations:["Honeypots have nothing to do with actual honey bees or sustainability programs; the term is a security deception metaphor entirely unrelated to beekeeping.","A honeypot mimics a real system, making it attractive to attackers; any interaction with it is suspicious, enabling detection and intelligence gathering on attacker behavior.","Certificate storage is handled by certificate authorities and trust stores; a honeypot is instead a deception system designed to lure attackers.","Perimeter traffic blocking is performed by firewalls and intrusion prevention systems; a honeypot instead deliberately allows attackers in to monitor their actions."]},
  {id:394,domain:T,question:"What is DNS hijacking?",options:["Registering domain names shortly after their previous legitimate owner allowed them to expire","Modifying DNS settings on a victim's device or router to redirect queries to attacker-controlled resolvers","Flooding a target's DNS servers with an overwhelming volume of simultaneous lookup queries","Creating wildcard DNS records that resolve any requested subdomain to a single configured address"],answer:1,explanation:"DNS hijacking redirects victims through malicious resolvers that can modify all DNS responses, enabling MitM attacks, phishing, and traffic interception.",optionExplanations:["Registering expired domains describes domain squatting or drop-catching; hijacking instead modifies existing DNS settings on a victim's own device or router.","DNS hijacking changes the DNS resolver settings on a device or router (via malware, router exploitation, or ISP manipulation) so all DNS queries go through attacker-controlled infrastructure.","Flooding DNS servers with queries is a denial-of-service attack; hijacking instead redirects resolution to attacker infrastructure rather than disrupting availability.","Wildcard DNS records are a legitimate, intentional DNS configuration feature; hijacking is instead an attack that modifies the DNS resolution path itself."]},
  {id:395,domain:G,question:"What is elliptic curve cryptography (ECC)?",options:["A symmetric block cipher algorithm that encrypts plaintext data in fixed-size chunks of bits","An asymmetric approach using elliptic curve mathematics to achieve RSA-equivalent security with smaller keys","A family of cryptographic hash functions producing fixed-length message digests from input","A symmetric key exchange protocol used specifically to negotiate a shared secret encryption key"],answer:1,explanation:"ECC achieves equivalent security to RSA-2048 with only 256-bit keys, making it ideal for resource-constrained devices and mobile applications.",optionExplanations:["Block ciphers such as AES and DES are symmetric encryption algorithms; ECC is instead an entirely asymmetric cryptographic system.","ECC uses algebraic structures of elliptic curves over finite fields to create public/private key pairs — ECDSA for signatures, ECDH for key exchange — with smaller keys than RSA.","Hash function families such as SHA produce fixed-length digests from input data; ECC is instead an asymmetric public/private key algorithm.","Symmetric key exchange protocols negotiate shared secrets between two parties; ECDH is the elliptic curve variant of Diffie-Hellman, but ECC itself is fundamentally asymmetric."]},
  {id:396,domain:P,question:"What is consent management in data privacy?",options:["Managing and provisioning system administrator access rights and elevated privileges across systems","Processes and systems for obtaining, recording, and honoring individuals' consent about their personal data","Formally approving proposed configuration changes to newly deployed security tools and platforms","Negotiating and managing the legal contracts an organization signs with its external data processors"],answer:1,explanation:"Consent management is critical for GDPR compliance — organizations must obtain specific, informed consent and be able to prove it and honor withdrawals.",optionExplanations:["System administrator access rights are managed by identity and access management systems; consent management instead governs data subject permissions over their own data.","Consent management captures when, how, and for what purposes individuals agreed to data processing, maintains records, and enforces consent-based restrictions across systems.","Security configuration approval is a change management function within IT operations; consent management instead concerns individual rights over their personal data.","Legal contracts with data processors are formalized as data processing agreements; consent management instead concerns the relationship between organizations and individual data subjects."]},
  {id:397,domain:A,question:"What is the zero trust security model?",options:["Automatically trusting all traffic that originates from inside the internal corporate network","A security framework requiring verification of every user, device, and connection before granting access","Completely prohibiting all employees from ever accessing any sensitive organizational data","Blocking every external network connection attempt regardless of its source or purpose"],answer:1,explanation:"Zero trust ('never trust, always verify') eliminates the concept of a trusted internal network — all access requires authentication, authorization, and continuous validation.",optionExplanations:["Implicitly trusting internal traffic describes the traditional perimeter security model; zero trust explicitly rejects this assumption entirely.","Zero trust requires verifying identity, device health, and context for every access request — even from inside the corporate network — and grants least-privilege access to specific resources.","Zero trust is about rigorously verifying access, not about categorically blocking employees from accessing sensitive data they legitimately need.","Blocking all external connections describes an extreme network isolation approach; zero trust instead allows connections but rigorously verifies them before granting access."]},
  {id:398,domain:O,question:"What is a security baseline?",options:["The minimum acceptable security configuration for a system or device, established through policies and hardening guides","The single weakest and most vulnerable point of security found anywhere across an organization's systems","A specialized monitoring tool used for continuously measuring and analyzing network traffic patterns","The initial reconnaissance starting point testers use when beginning a penetration test engagement"],answer:0,explanation:"Security baselines define minimum required configurations (patching, disabled services, password policies) ensuring consistent security posture across similar systems.",optionExplanations:["A security baseline defines the minimum required security configuration — OS hardening settings, disabled unnecessary services, configured logging — against which systems are compared.","The lowest security point describes an individual vulnerability finding; a baseline is instead a defined minimum configuration standard to which systems are compared.","Network traffic measurement tools are flow analyzers and packet capture utilities; a baseline is instead a defined configuration standard, not a monitoring tool.","Penetration tests begin from an attacker's offensive perspective during reconnaissance; baselines are instead defensive configuration standards unrelated to test scoping."]},
  {id:399,domain:T,question:"What is tailgating in physical security?",options:["Covertly following and monitoring someone's online activity to gather personal information over time","Gaining unauthorized physical access to a secured area by closely following an authorized person inside","Covertly attaching a malicious hardware implant to the back panel of a physical server","Intercepting a target's wireless communications from a hidden position near their physical location"],answer:1,explanation:"Tailgating bypasses physical access controls (key cards, PINs) by piggybacking on an authorized person's entry — social courtesy enables the attack.",optionExplanations:["Following someone's online activity to gather information describes cyberstalking or OSINT reconnaissance; tailgating instead refers to unauthorized physical entry into a facility.","Tailgating (or piggybacking) exploits people's tendency to hold doors open — an attacker enters a secure area immediately after an authorized person without using their own credentials.","Attaching malicious hardware devices to servers is a hardware-based attack technique; tailgating instead is specifically about gaining physical entry to a facility.","Intercepting communications describes a man-in-the-middle or eavesdropping attack; tailgating is instead a physical security breach technique involving unauthorized building entry."]},
  {id:400,domain:G,question:"What is the Diffie-Hellman key exchange?",options:["A symmetric encryption algorithm that uses a single shared key to encrypt large volumes of data","A method allowing two parties to establish a shared secret over an insecure channel without prior keys","A cryptographic hash function used to generate condensed digests for digital signatures","A protocol used by certificate authorities specifically to publish certificate revocation status"],answer:1,explanation:"DH enables two parties to derive the same shared secret using public values and private values, without ever transmitting the secret itself.",optionExplanations:["Diffie-Hellman is a key exchange protocol rather than an encryption algorithm; it establishes a shared key but does not itself encrypt any data.","Diffie-Hellman uses mathematical properties of modular exponentiation — each party contributes public values, and the mathematics produces the same shared secret on both ends without it ever crossing the network.","Hash functions like SHA produce fixed-length digests for signing; Diffie-Hellman instead establishes a shared secret for subsequent use in symmetric encryption.","CRL and OCSP are the actual mechanisms that handle certificate revocation; Diffie-Hellman is instead a key exchange mechanism used in TLS, IPsec, and SSH."]},
  {id:401,domain:T,question:"What is vishing?",options:["A visually deceptive phishing technique that uses fabricated deepfake video content to trick victims","Voice phishing — using phone calls to deceive victims into revealing sensitive information or performing actions","A phishing attack that specifically exploits vulnerabilities within an organization's VoIP telephone systems","Sending fraudulent phishing messages directly to victims through text-based SMS communications"],answer:1,explanation:"Vishing attacks impersonate banks, IRS, tech support, or government agencies via phone, creating urgency to extract credentials, SSNs, or payments.",optionExplanations:["Visual phishing using fabricated deepfake videos describes an emerging deepfake-based attack; vishing is instead specifically conducted over voice phone calls.","Vishing (voice phishing) uses phone calls — often spoofing caller ID — to impersonate trusted entities and pressure victims into revealing sensitive information.","Attacks targeting VoIP system vulnerabilities are VoIP-specific technical attacks; vishing instead describes the social engineering technique itself, regardless of the phone technology used.","SMS-based phishing is properly called smishing; vishing instead specifically refers to voice call-based phishing attacks."]},
  {id:402,domain:A,question:"What is infrastructure as code (IaC) from a security perspective?",options:["Writing custom exploit code specifically designed to attack and compromise IT infrastructure","Defining IT infrastructure through machine-readable files, enabling consistent, version-controlled deployments","Completely replacing human infrastructure teams with fully autonomous, unsupervised deployment systems","A specialized technique focused purely on optimizing and reducing ongoing cloud infrastructure costs"],answer:1,explanation:"IaC enables security review of infrastructure configurations, consistent secure deployments, and detection of configuration drift through code review and scanning.",optionExplanations:["Writing exploit code to attack infrastructure describes offensive penetration testing activity; IaC is instead a defensive DevOps and security management practice.","IaC (Terraform, CloudFormation, Ansible) treats infrastructure configuration as code — enabling peer review, version control, automated security scanning, and reproducible deployments.","IaC tools automate repetitive deployment tasks but do not eliminate teams; they instead provide tools letting smaller teams securely manage larger environments.","Cloud cost management relies on dedicated cost optimization tools and practices; IaC is instead primarily about consistent, automated infrastructure deployment."]},
  {id:403,domain:O,question:"What is purple teaming?",options:["A single hybrid team whose members literally wear both red and blue colored uniforms","A collaborative exercise where red team and blue team work together to maximize learning together","A specialized penetration testing team focused exclusively on web application vulnerabilities","A realistic simulation designed specifically to emulate the tactics of an advanced persistent threat"],answer:1,explanation:"Purple teaming breaks down the adversarial separation of red vs. blue, creating collaborative learning sessions that improve both offensive techniques and defensive detections.",optionExplanations:["The purple color metaphor refers to blending red (attack) and blue (defense) roles and knowledge, not to any literal uniform color scheme.","Purple teaming has red team attackers share techniques in real-time with blue team defenders, who then tune detections and responses — creating immediate feedback loops for security improvement.","Web application penetration testing describes a specific type of red team engagement; purple teaming is instead a broader collaborative methodology between red and blue.","APT simulations can be incorporated into purple team exercises, but purple teaming is specifically defined by its collaborative, knowledge-sharing structure between teams."]},
  {id:404,domain:T,question:"What is a logic bomb?",options:["Self-propagating malware that automatically replicates itself across connected network shares and hosts","Malicious code that executes when specific trigger conditions are met, such as a date/time or specific event","A memory corruption exploit that deliberately triggers a buffer overflow condition in vulnerable software","A denial-of-service attack that is unintentionally triggered by flawed application logic errors"],answer:1,explanation:"Logic bombs are often planted by insiders (disgruntled employees) and can destroy data, disrupt operations, or exfiltrate information when conditions trigger.",optionExplanations:["Self-replicating network malware describes a worm; a logic bomb instead remains completely dormant until a specific trigger condition activates it.","Logic bombs lay dormant until a condition is met — a specific date (Friday 13th), a username being deleted, or a file being opened — then execute their payload.","Buffer overflow exploits are code exploitation techniques targeting memory handling; logic bombs are instead concealed malicious code that waits for a trigger.","DoS attacks aim to cause unavailability through resource exhaustion; logic bombs are instead concealed payloads that intentionally activate when specific conditions are satisfied."]},
  {id:405,domain:G,question:"What is stream ciphers vs. block ciphers?",options:["Stream ciphers always process data more slowly, while block ciphers are inherently always faster","Stream ciphers encrypt data one bit or byte at a time; block ciphers encrypt fixed-size chunks of data","Block ciphers are exclusively reserved for wireless networking protocols; stream ciphers are used only on wired networks","Stream cipher and block cipher are simply two different marketing names for one identical algorithm type"],answer:1,explanation:"Stream ciphers (RC4) are fast and good for real-time communications; block ciphers (AES) are used for bulk data encryption with modes like CBC or GCM.",optionExplanations:["Actual speed depends heavily on the specific implementation and use case — stream ciphers can be very fast, and hardware-accelerated block ciphers can be too.","Stream ciphers generate a keystream and XOR it with plaintext bit-by-bit; block ciphers divide plaintext into fixed blocks (128-bit for AES) and encrypt each block.","Both cipher types can actually be used in any network context; the choice depends on performance needs and security requirements, not the network medium.","Stream and block ciphers are fundamentally different cryptographic approaches with distinct designs, not merely alternate names for the same underlying algorithm."]},
  {id:406,domain:P,question:"What is the purpose of a data processing agreement (DPA)?",options:["A standard commercial contract governing the purchase and licensing of third-party software","A legally required contract defining how personal data is processed, protected, and handled","A service agreement covering the ongoing technical maintenance and support of IT systems","A service level agreement defining response times and availability guarantees for IT support"],answer:1,explanation:"DPAs (required by GDPR Article 28) ensure data processors implement appropriate security and only process data per the controller's instructions.",optionExplanations:["Software license purchase contracts are ordinary vendor procurement agreements; a DPA instead specifically governs personal data processing responsibilities between parties.","A DPA establishes obligations for how a service provider processes personal data — security requirements, subprocessor restrictions, audit rights, breach notification timelines, and data deletion.","System maintenance agreements cover general IT support services; a DPA instead specifically addresses the personal data handling obligations of a service provider.","SLAs define service availability, response times, and performance guarantees; a DPA instead defines data protection responsibilities and legal obligations for personal data processing."]},
  {id:407,domain:A,question:"What is a security information and event management (SIEM) system's primary function?",options:["Encrypting log data while it is transmitted from source systems to a central collector","Collecting, normalizing, and correlating security events from multiple sources to detect threats","Automatically generating formatted compliance reports required for periodic regulatory audits","Performing scheduled vulnerability assessments and scans across every host on the network"],answer:1,explanation:"SIEMs aggregate events from firewalls, endpoints, applications, and cloud to detect patterns that individual tools cannot see in isolation.",optionExplanations:["Log encryption during transmission is handled by the underlying transport protocol such as TLS; a SIEM's core function is instead correlation and analysis.","SIEM platforms collect logs from diverse sources, normalize them to a common format, apply correlation rules to detect threats, and alert analysts — providing a unified security monitoring capability.","Compliance reporting is a useful secondary SIEM capability; correlation and threat detection is instead the platform's primary security purpose.","Vulnerability assessments are performed by specialized scanning tools such as Nessus or Qualys; a SIEM instead focuses on runtime event monitoring and correlation."]},
  {id:408,domain:T,question:"What is cross-site request forgery (CSRF)?",options:["Directly stealing a victim's active browser session cookies through interception or malware in order to fully impersonate their authenticated identity","An attack that tricks an authenticated user into unknowingly submitting a forged request to a web application, exploiting the application's trust in the user","Injecting malicious client-side scripts directly into web pages that are later viewed and executed by other unsuspecting users","Actively intercepting and reading HTTP requests as they travel between the client's browser and the destination server"],answer:1,explanation:"CSRF exploits the browser's automatic inclusion of authentication cookies — a victim visiting a malicious site unknowingly triggers authenticated actions on another site.",optionExplanations:["Stealing session cookies describes session hijacking or an XSS-based attack; CSRF does not require stealing any cookies — it instead exploits the browser's automatic cookie submission.","CSRF tricks the browser into making authenticated requests to target sites — if the victim is logged into their bank, an evil site can trigger fund transfers without the victim knowing.","Injecting malicious scripts into pages viewed by others describes Cross-Site Scripting (XSS); CSRF instead forges requests rather than injecting any script code.","Request interception describes a man-in-the-middle attack; CSRF instead manipulates the victim's own authenticated browser session to submit forged requests from a malicious site."]},
  {id:409,domain:O,question:"What is an intrusion prevention system (IPS) and how does it differ from an IDS?",options:["An IPS only passively detects intrusions, while an IDS is instead the system that actively prevents them","An IDS monitors and alerts on suspicious activity; an IPS monitors and actively blocks or mitigates suspicious activity","IDS and IPS perform functionally identical detection tasks, differing only in the underlying network protocols they use","An IPS can only be deployed as software, while an IDS can only be deployed as a dedicated hardware appliance"],answer:1,explanation:"An IDS is passive (alerts only); an IPS is inline and active (detects and blocks). Both use signatures and anomaly detection but IPS can respond automatically.",optionExplanations:["This description has the roles reversed — an IDS is actually the one that detects and alerts, while an IPS is the one that detects and prevents.","IDS sensors are typically passive (receive a copy of traffic); IPS sensors sit inline and can drop, reset, or modify malicious traffic in real-time.","IDS and IPS can detect the same categories of attacks, but the meaningful difference is the ability to actively block traffic versus only generating an alert.","Both IDS and IPS can actually be implemented as either hardware appliances or software; the real distinction is passive monitoring versus active inline prevention."]},
  {id:410,domain:G,question:"What is biometric authentication and its primary security risk?",options:["Using a device's geographic location data for authentication — the primary risk is attackers spoofing GPS coordinates","Using unique biological characteristics for authentication — primary risk is that biometrics cannot be changed if compromised","Using behavioral patterns like typing rhythm for access control — the primary risk is attackers learning to predict those patterns","Using installed device certificates for authentication — the primary risk is attackers stealing and reusing those certificates"],answer:1,explanation:"Fingerprints, iris scans, and face recognition authenticate uniquely but if compromised (database breach), users cannot get new fingerprints like they can new passwords.",optionExplanations:["Location-based authentication relies on GPS or IP geolocation data rather than biological traits; biometrics instead use physical or behavioral characteristics of the person.","Biometric authentication uses fingerprints, retinas, voiceprints, or facial features — uniquely identifying but immutable; if a biometric database is breached, affected individuals are permanently compromised.","Behavioral biometrics such as typing rhythm and gait are actually a subtype of biometrics; the primary concern across all biometric data is its permanent immutability, not predictability.","Device certificates are a form of certificate-based authentication tied to a machine; biometrics instead rely on a person's own biological measurements."]},
  {id:411,domain:T,question:"What is a Trojan horse in cybersecurity?",options:["A self-replicating virus that automatically attaches itself to other executable program files","Malware disguised as legitimate software that performs malicious actions while appearing normal","A self-propagating network worm that automatically spreads to victims through email attachments","Malware that encrypts a victim's files and then demands payment of a ransom for their release"],answer:1,explanation:"Trojans rely on social engineering — users willingly install what appears to be useful software that secretly installs backdoors, RATs, or credential stealers.",optionExplanations:["Self-replicating code that infects files describes a virus or worm; Trojans do not self-replicate at all — they instead rely entirely on users to install them.","A Trojan (named after the mythological Trojan horse) appears as legitimate or desirable software (game, utility, update) while secretly performing malicious actions in the background.","Network worms spread autonomously through networks and email without user action; Trojans instead require the user to willingly install them and do not self-propagate.","File-encrypting malware demanding payment describes ransomware; a Trojan is instead the delivery and concealment mechanism that can be used to deliver ransomware or other payloads."]},
  {id:412,domain:A,question:"What is API security and why is it critical in modern architectures?",options:["Securing physical access to the server racks and hardware hosting application infrastructure","Protecting application interfaces from abuse and exploitation, since APIs now handle most data exchange","Encrypting network packets purely at the transport layer as they travel across the network","Managing the issuance, renewal, and rotation of SSL certificates for public-facing web services"],answer:1,explanation:"APIs expose business logic and data directly — OWASP API Security Top 10 covers broken object level authorization, excessive data exposure, and injection attacks specific to APIs.",optionExplanations:["Physical server access security is a data center control; API security instead protects the software interfaces that applications expose to each other.","API security addresses authentication, authorization, rate limiting, input validation, and output filtering for the programmatic interfaces that modern applications use to communicate.","Transport layer encryption such as TLS is one component supporting API security but does not by itself address authorization or application-layer API attacks.","SSL certificate management is a supporting activity for securing communications; API security is instead a much broader discipline covering the entire API lifecycle and threat surface."]},
  {id:413,domain:O,question:"What is change management in IT security?",options:["Managing large-scale organizational restructuring efforts including staffing and reporting changes","A formal process for requesting, reviewing, approving, and documenting changes to IT systems","Managing version control history and branching strategy for an organization's source code","Routinely updating individual employee access permissions as roles and responsibilities change"],answer:1,explanation:"Change management prevents outages and security incidents caused by unauthorized, poorly tested, or conflicting changes to production systems.",optionExplanations:["Organizational restructuring is an HR and executive management function; IT change management instead governs modifications made to technical systems.","Change management (using tools like ServiceNow) requires formal requests, risk assessment, approval (CAB review), testing, implementation windows, and rollback plans before any production change.","Version control tools like Git are developer tools tracking code history; change management is instead the broader governance process controlling what reaches production and when.","Access permission updates are an identity and access management function; change management instead controls all types of changes made to IT infrastructure and systems."]},
  {id:414,domain:T,question:"What is a brute force attack?",options:["A direct physical attack targeting an organization's cabling and network infrastructure equipment","Systematically trying all possible combinations of passwords or keys until the correct one is found","Using deceptive social engineering tactics to trick a victim into revealing their password","Exploiting a known software vulnerability to completely bypass an application's authentication mechanism"],answer:1,explanation:"Brute force attacks are resource-intensive but guaranteed to succeed given time — countermeasures include account lockouts, CAPTCHAs, and rate limiting.",optionExplanations:["Physical attacks on network infrastructure are hardware-level intrusions; brute force is instead a purely systematic computational authentication attack.","Brute force tries every possible password or key — in order or random — until finding the correct one. Against long, complex passwords this is computationally infeasible.","Using social engineering to obtain passwords describes phishing or pretexting; brute force is instead purely computational and requires no victim interaction.","Exploiting software vulnerabilities is an exploit-based attack technique; brute force instead systematically tests credential combinations rather than exploiting a code flaw."]},
  {id:415,domain:G,question:"What is steganography?",options:["A technical method used for compressing data to significantly reduce its overall file size","The practice of hiding secret information within ordinary, non-secret files to avoid detection","Encrypting data repeatedly using multiple successive layers of different encryption algorithms","A technique for embedding invisible ownership watermarks into copyrighted digital media content"],answer:1,explanation:"Steganography hides the existence of a message (vs. encryption which hides the meaning) — attackers use it to exfiltrate data hidden in images uploaded to public sites.",optionExplanations:["Data compression is aimed at reducing file size; steganography instead hides information within files without necessarily changing their size in any noticeable way.","Steganography conceals messages within carrier files — hiding text in the least significant bits of image pixels, inaudible audio frequencies, or document whitespace — so observers don't know a message exists.","Applying multiple layers of encryption is a defense-in-depth encryption technique; steganography is instead about concealment, not about encrypting data at all.","Digital watermarking embeds ownership information to prove authorship; steganography instead embeds secret messages — both hide data in files but serve very different purposes."]},
  {id:416,domain:P,question:"What is the difference between a data controller and a data processor under GDPR?",options:["Controllers and processors always refer to the same legal entity under two different job titles","A controller determines the purposes and means of processing data; a processor acts on its instructions","Controllers are solely responsible for actively processing data, while processors only store it","Data processors bear greater overall legal responsibility under GDPR than the controllers who hired them"],answer:1,explanation:"A hospital (controller) decides what patient data to collect; their cloud backup provider (processor) stores it per the hospital's instructions. Controllers bear primary GDPR responsibility.",optionExplanations:["Controllers and processors are actually distinct legal roles under GDPR, each carrying different obligations, not simply different titles for the same entity.","Controllers make decisions about what data to collect and why; processors act on the controller's behalf. A SaaS vendor may be a controller for their users' data and a processor for their customers' data.","Both controllers and processors can actually perform processing and storage activities; the real distinction is who decides the purpose and means of that processing.","This reverses the actual allocation of responsibility — controllers bear primary GDPR compliance responsibility, while processors have narrower contractual and direct obligations."]},
  {id:417,domain:A,question:"What is Defense in Depth?",options:["Building a single, theoretically impenetrable security layer strong enough to stop every possible attack","Implementing multiple overlapping security layers so that if one fails, others remain to detect or prevent an attack","Applying military-grade defense encryption standards uniformly to every piece of organizational data","Concentrating essentially all available security resources and budget solely on perimeter defense"],answer:1,explanation:"Defense in depth assumes breaches will occur and ensures that no single point of failure can compromise the entire organization — multiple layers buy time for detection.",optionExplanations:["Relying on one impenetrable layer is the opposite of defense in depth, which recognizes that no single security control is ever truly perfect.","Defense in depth (or layered security) uses network firewalls, endpoint protection, encryption, access controls, monitoring, and physical security together so attackers must defeat multiple controls.","Strong encryption is just one possible layer among many; defense in depth is instead the architectural strategy of combining many different types of controls together.","Focusing only on the perimeter is the old castle-and-moat model; defense in depth instead distributes security controls throughout the entire environment."]},
  {id:418,domain:O,question:"What is vulnerability management?",options:["Tracking and managing purchased software licenses to ensure ongoing compliance and cost efficiency","A continuous process of identifying, classifying, remediating, and mitigating vulnerabilities in IT systems","Conducting a formal review of security configurations just once during an annual audit cycle","Managing staffing levels, schedules, and resource allocation for the security team"],answer:1,explanation:"Vulnerability management prioritizes remediation by risk severity, tracks remediation progress, and measures the organization's patch compliance over time.",optionExplanations:["Software license tracking is an asset and procurement management function; vulnerability management instead focuses specifically on identifying and fixing security weaknesses.","Vulnerability management uses scanning tools, tracks findings, prioritizes by CVSS score and exploitability, assigns remediation to owners, and validates fixes — creating a continuous improvement cycle.","Annual configuration audits are a point-in-time review; vulnerability management is instead continuous, addressing the constant discovery of new vulnerabilities.","Security team resource management is an HR and operations function; vulnerability management is instead a security program addressing technical weaknesses in systems."]},
  {id:419,domain:T,question:"What is an SQL injection attack?",options:["Directly inserting corrupted or malformed data records into an organization's backend database","Inserting malicious SQL code into input fields to manipulate queries, potentially exposing data","Flooding a database's SQL servers with an excessive volume of simultaneous queries","Running custom SQL administrative scripts to escalate an account's assigned database privileges"],answer:1,explanation:"SQL injection exploits applications that build queries by concatenating user input — attackers inject SQL that changes query logic to dump, modify, or delete data.",optionExplanations:["SQL injection does not simply insert arbitrary data into a database — it instead changes the structure and logic of the queries themselves through malicious input.","SQL injection works by breaking out of the intended query structure using characters like ' or --, then appending attacker-controlled SQL that changes what the database does.","Flooding SQL servers with excessive queries describes a database denial-of-service attack; SQL injection instead targets query logic through application input fields.","SQL injection may sometimes be used as one technique to escalate privileges, but the term itself refers to the underlying input manipulation technique, not privilege escalation."]},
  {id:420,domain:G,question:"What is the principle of defense through diversity?",options:["Building a security team composed of members with diverse professional and educational backgrounds","Using different vendors of security controls so one vulnerability cannot compromise every layer at once","Storing and protecting sensitive data simultaneously across several different file formats","Applying a different, unique encryption algorithm to every distinct category of stored data"],answer:1,explanation:"Monocultures (same OS everywhere) create single points of failure — a single exploit can compromise all systems. Diversity limits the blast radius of any single vulnerability.",optionExplanations:["Team diversity is valuable for many organizational reasons; defense through diversity specifically refers instead to technology diversity among deployed security controls.","Using diverse technologies means a zero-day in one vendor's firewall doesn't also defeat all other security layers — each layer has different attack surfaces and vulnerabilities.","Protecting data stored in multiple formats does not address the resilience of security controls; technology diversity among those controls does.","Using different encryption algorithms per data type creates compatibility issues without a clear security benefit; diversity instead refers to using different vendors and types of layered security controls."]},
  {id:421,domain:T,question:"What is a botnet?",options:["A network of automated security bots deployed to continuously monitor systems for threats","A network of compromised computers controlled by an attacker and used to conduct coordinated attacks","A legitimate automation network used by IT teams to schedule and execute routine tasks","A decentralized peer-to-peer network used by ordinary users to legally share files"],answer:1,explanation:"Botnets are used for DDoS attacks, spam campaigns, credential stuffing, cryptomining, and proxy services — the botmaster profits while victims bear costs.",optionExplanations:["Automated security monitoring bots are legitimate defensive tools; a botnet instead consists of compromised victim machines placed under an attacker's control.","A botnet coordinates thousands to millions of compromised machines (zombies) for attacker purposes — the infected machines' owners typically don't know they're participating.","Legitimate IT automation uses tools such as Ansible or scheduled scripts; a botnet instead uses malware-infected computers for malicious purposes.","Peer-to-peer networks enable legitimate file sharing between willing participants; a botnet is instead a malicious network of compromised computers serving an attacker."]},
  {id:422,domain:A,question:"What is a secure software development lifecycle (SSDLC)?",options:["Restricting a development project to using only vetted, pre-approved open-source components","Integrating security activities into every development phase from requirements through deployment","Performing a single round of security testing immediately before the software's final release","Hiring outside security experts to review completed code only after development has finished"],answer:1,explanation:"SSDLC (like Microsoft SDL or OWASP SAMM) integrates threat modeling, secure coding, SAST/DAST, and security training throughout development to reduce vulnerabilities.",optionExplanations:["Restricting a project to open-source components is a procurement and licensing decision; SSDLC is instead a development process framework spanning the entire lifecycle.","SSDLC includes security requirements definition, threat modeling in design, secure coding standards, automated scanning (SAST/DAST), penetration testing, and secure deployment procedures.","Testing only right before release is a security bolt-on approach; SSDLC instead integrates security starting from the earliest requirements phase.","Code review by outside security experts is one useful SSDLC activity among many; SSDLC is the broader lifecycle integrating security throughout all development phases."]},
  {id:423,domain:O,question:"What is a security risk register?",options:["A procurement list cataloging approved security tool vendors and their contract terms","A documented inventory of identified security risks, their likelihood, impact, and assigned owners with mitigation status","A chronological log recording every security incident that has occurred within the organization","A technical database cataloging known software vulnerabilities discovered across the organization's systems"],answer:1,explanation:"Risk registers provide governance visibility into organizational risk posture, enabling prioritization of mitigation efforts and tracking progress over time.",optionExplanations:["Vendor lists are procurement and asset management records; a risk register instead documents identified security risks and how they are being managed.","A risk register catalogs each identified risk with its probability, potential impact, risk score, who owns it, what mitigations are in place, and current status — driving risk-based security decisions.","Incident logs record past events that have already happened; a risk register instead tracks potential future adverse events and their ongoing management.","Vulnerability databases list specific technical weaknesses in systems; a risk register instead assesses broader business-level risks that may stem from vulnerabilities or other sources."]},
  {id:424,domain:T,question:"What is port scanning?",options:["Automatically scanning outgoing documents for sensitive content before they are emailed externally","Probing network ports on target systems to identify open ports and running services for reconnaissance","Physically monitoring wall and switch network ports for the connection of unauthorized devices","Scanning inbound email server ports specifically to detect and filter incoming spam messages"],answer:1,explanation:"Port scanning (Nmap, Masscan) is reconnaissance that maps attack surface — identifying web servers, databases, SSH services, and other accessible services on a target.",optionExplanations:["Scanning outgoing documents for sensitive content is a data loss prevention function; port scanning instead probes a target's network communication endpoints.","Port scanning sends probe packets to determine which TCP/UDP ports are open, helping identify what services run on a host and potential attack entry points.","Monitoring physical switch ports for rogue devices is a network access control function; port scanning is instead a remote network reconnaissance technique.","Email spam filtering is an email security gateway function; port scanning instead probes network ports broadly to discover available services on a host."]},
  {id:425,domain:G,question:"What is multi-factor authentication (MFA)?",options:["Requiring a user to enter two or more separate passwords sequentially for a single account","Requiring two or more independent verification factors (something you know, have, or are) before granting access","Requiring a user to correctly answer multiple security questions during an account recovery process","Requiring formal sign-off approval from multiple separate administrators before granting a user access"],answer:1,explanation:"MFA dramatically reduces account takeover risk — even if credentials are stolen, attackers need the second factor (TOTP, hardware key, push notification) to gain access.",optionExplanations:["Using multiple passwords is still only a single factor category (something you know); MFA instead requires factors drawn from genuinely different categories.","MFA combines factors from different categories: knowledge (password), possession (phone/token), and inherence (biometric) — requiring multiple independent factors that attackers must all compromise.","Security questions are all still knowledge-based factors; genuine MFA instead requires factors from different categories to provide real additional security.","Requiring multiple administrator approvals is an administrative workflow control; MFA is instead a technical authentication mechanism requiring multiple independent factor types from the user."]},
  {id:426,domain:P,question:"What is data minimization?",options:["Compressing and archiving collected data using algorithms designed to reduce long-term storage and infrastructure costs","Collecting and retaining only the personal data that is strictly necessary for the specified purpose being pursued","Automatically anonymizing all collected data immediately so it can never be linked back to an identifiable individual","Limiting the number of employees who are granted account privileges to view or modify stored personal data records"],answer:1,explanation:"Data minimization (GDPR Article 5) reduces privacy risk by limiting collection scope — data you don't collect cannot be breached or misused.",optionExplanations:["Data compression is a technical storage optimization; data minimization is a privacy principle about what data is collected in the first place, not how it is stored.","Data minimization means not collecting more personal data than needed for the explicit purpose — if a service needs an email for account recovery, it shouldn't also collect date of birth, phone number, and address.","Anonymization transforms data so individuals can't be identified after the fact; minimization instead limits what is collected in the first place, before anonymization would even apply.","Access limitation is the principle of least privilege for internal data access; minimization limits the volume and scope of what is collected from data subjects."]},
  {id:427,domain:A,question:"What is a cloud access security broker (CASB)?",options:["An internal security team employed and managed directly by the cloud service provider to protect its own infrastructure","A security policy enforcement point between cloud service users and cloud providers that monitors and controls cloud service usage","A cloud-hosted certificate authority that issues and manages digital certificates for encrypted cloud application traffic","An authentication service that verifies user identities before granting access to subscribed cloud applications"],answer:1,explanation:"CASBs provide visibility into shadow IT, enforce data loss prevention, detect threats in cloud apps, and apply compliance controls to cloud service usage.",optionExplanations:["Cloud provider security teams are internal to the CSP and protect the provider's own infrastructure; a CASB is a separate, customer-controlled security layer sitting between users and providers.","A CASB sits between users and cloud services (Office 365, Salesforce, Box), providing visibility, access control, threat detection, and data protection across all cloud usage.","Certificate authorities issue and manage certificates for encryption; a CASB instead controls and monitors how cloud services are actually used by an organization.","Authentication services (IdPs) handle identity verification; a CASB enforces broader security policies on top of already-authenticated cloud service access."]},
  {id:428,domain:O,question:"What is security awareness training?",options:["Specialized technical training courses designed exclusively for dedicated security engineers and network analysts","Education programs that teach all employees to recognize and respond appropriately to common security threats","Hands-on training sessions that teach general staff how to operate specific commercial security software tools","Advanced, highly technical training curricula reserved exclusively for professional penetration testers and red teams"],answer:1,explanation:"Humans are the most exploited attack vector — awareness training addresses phishing recognition, password hygiene, social engineering, and reporting suspicious activity.",optionExplanations:["Technical training for engineers is specialized and narrow; security awareness is designed for all employees regardless of technical role.","Security awareness training covers phishing recognition, safe browsing, social engineering tactics, physical security (tailgating), password management, and how to report security concerns.","Security tool training is technical skill development for using specific software; awareness training builds general security knowledge across the entire workforce.","Penetration tester training is a specialized technical curriculum for security professionals; security awareness is broad education aimed at non-security employees."]},
  {id:429,domain:T,question:"What is an exploit kit?",options:["A documentation toolkit used by security researchers to responsibly catalog and describe known software exploits","Automated attack tools that probe visiting browsers for vulnerabilities and exploit them to silently deliver malware","A curated collection of proof-of-concept exploits used strictly for authorized penetration testing exercises","Vendor-supplied software used to develop, test, and distribute official patches for known software vulnerabilities"],answer:1,explanation:"Exploit kits (RIG, Magnitude) check browser fingerprints and automatically deliver appropriate exploits — a single drive-by download visit can result in malware installation.",optionExplanations:["Security researcher toolkits are legitimate documentation and research tools; exploit kits are malicious automated attack platforms deployed against victims.","Exploit kits are deployed on compromised or malicious websites and automatically detect and exploit unpatched browser vulnerabilities to deliver ransomware, banking trojans, or other malware.","Proof-of-concept exploit collections used in authorized testing are research and assessment tools; exploit kits are weaponized automation platforms for mass exploitation of victims.","Patch management tools are built by vendors to fix vulnerabilities; exploit kits instead exploit those same vulnerabilities before or after a patch exists."]},
  {id:430,domain:G,question:"What is an access control list (ACL)?",options:["A curated list of software applications that have been formally approved for installation on endpoints","A set of rules that control what traffic is permitted through a device or which actions subjects can perform on objects","A centralized registry that records and tracks every user account created within an organization's directory","A maintained list identifying specific websites or IP addresses that have been permanently blocked from being reached"],answer:1,explanation:"ACLs on routers/firewalls control network traffic; ACLs on file systems control who can read, write, or execute files — both implement discretionary or mandatory access control.",optionExplanations:["Approved software lists are application whitelists governing installation; ACLs instead control access to network resources or system objects.","ACLs define permissions — network ACLs permit/deny traffic based on IP/port/protocol; filesystem ACLs define what users or groups can do with files and directories.","User account registries are managed by directory services like Active Directory; ACLs reference those existing accounts to define their permissions on resources.","Blocked website lists are web filter configurations or deny-list ACLs; ACLs are the broader mechanism that can both allow and deny access to many resource types."]},
  {id:431,domain:T,question:"What is spear phishing?",options:["A phishing technique named after spearguns purely as a marketing metaphor with no real targeting element","Highly targeted phishing attacks customized with personal victim information to increase believability and success","Large-scale, generic phishing campaigns sent broadly to every employee within an entire targeted organization","Voice-call-based phishing attacks in which an attacker impersonates a trusted contact over the telephone system"],answer:1,explanation:"Spear phishing uses reconnaissance (LinkedIn, social media, company website) to craft convincing lures — attackers know the victim's name, job, colleagues, and projects.",optionExplanations:["The spear metaphor contrasts with wide-net phishing; it refers to precision targeting of one victim, not any real weapon or purely decorative branding.","Spear phishing personalizes the attack: 'Hi John, your manager Sarah asked me to resend the Q3 report' — specificity makes victims far more likely to act.","Mass phishing campaigns sent broadly are generic phishing; spear phishing is instead targeted at specific individuals using personalized, researched content.","Voice phishing over the phone is vishing, a distinct technique; spear phishing uses email or digital messages with a highly targeted, researched approach."]},
  {id:432,domain:A,question:"What is a load balancer from a security perspective?",options:["A specialized device used purely to test how much traffic load a network link can theoretically handle","A system that distributes traffic across multiple servers, improving availability and enabling DDoS mitigation","A tool used strictly to throttle and cap the available bandwidth for individual users or applications","A monitoring appliance that passively tracks and reports overall network performance and latency statistics"],answer:1,explanation:"Load balancers improve resilience (no single server failure brings down the service) and can perform SSL offloading, WAF integration, and DDoS absorption.",optionExplanations:["Network load testing tools are performance testing instruments used before deployment; load balancers are production infrastructure handling live traffic.","Load balancers distribute requests across a pool of servers, enabling higher availability, horizontal scaling, and centralized application security controls like SSL inspection.","Bandwidth throttling is a QoS or rate-limiting function; load balancers instead distribute traffic across servers for availability and performance.","Network performance monitoring uses SNMP, NetFlow, and similar tools; load balancers actively route traffic, though they do collect some performance metrics."]},
  {id:433,domain:O,question:"What is the purpose of log retention policies?",options:["Minimizing storage expenses by deleting collected log data as quickly as technically possible after creation","Defining how long logs are kept to support incident investigation, compliance requirements, and forensic analysis","Automatically moving all generated log files to offline tape storage on a fixed recurring schedule","Establishing a single standardized log message format to be used consistently across all organizational systems"],answer:1,explanation:"Log retention must balance regulatory requirements (PCI DSS: 1 year, HIPAA: 6 years) with storage costs and investigation needs — logs deleted too early lose forensic value.",optionExplanations:["Deleting logs quickly is the opposite of an effective retention policy; logs need to be kept long enough to support investigations and compliance obligations.","Log retention policies specify retention periods for different log types (access logs, authentication logs, security events) to meet legal, regulatory, and investigative needs.","Log archiving to tape is a technical storage implementation detail; retention policies instead define the required retention periods and access requirements.","Log format standardization is a data collection configuration issue; retention policies govern how long to keep logs regardless of their format."]},
  {id:434,domain:T,question:"What is a pass-the-hash attack?",options:["Transferring a hashed copy of a file from one system to another for verification purposes","Using a captured password hash directly to authenticate to services without cracking the plaintext password","Silently intercepting hash values as they are transmitted in cleartext across an internal network segment","Deliberately engineering hash collisions in order to forge a valid-looking authentication credential"],answer:1,explanation:"Windows NTLM allows authentication with the hash directly — attackers extract hashes from memory (using Mimikatz) and use them for lateral movement.",optionExplanations:["Passing files between systems for verification is ordinary file transfer; pass-the-hash is instead a lateral movement technique used in authentication.","Pass-the-hash exploits NTLM authentication: if an attacker captures the NTLM hash from memory, they can authenticate as that user to other systems without knowing the actual password.","Network interception captures credentials as they travel; pass-the-hash instead reuses hashes already captured from memory, without needing to intercept a transmission.","Hash collisions enable a separate class of forgery attacks; pass-the-hash simply reuses legitimate captured hashes without needing to engineer any collision."]},
  {id:435,domain:G,question:"What is a digital certificate?",options:["An electronic scan or copy of a company's official government-issued business operating license","An electronic document that uses a digital signature from a trusted CA to bind a public key to an identity","A cryptographic signature value that has been separately applied to authenticate a single document","A user password that has been transformed and stored securely in irreversibly hashed form"],answer:1,explanation:"Digital certificates (X.509 standard) establish trusted identity for HTTPS, code signing, email encryption, and VPN authentication by binding public keys to verified identities.",optionExplanations:["Business licenses are legal documents unrelated to cryptography; digital certificates are cryptographic identity documents used for public key binding.","A digital certificate contains the subject's identity, their public key, validity period, issuing CA, and the CA's digital signature — clients verify the CA signature to trust the certificate.","A digital signature on a single document is what the CA applies during issuance; the certificate itself is the broader container holding that signature and the public key.","Passwords stored as hashes are authentication secrets used for login; digital certificates instead establish public key identity through CA-verified binding."]},
  {id:436,domain:P,question:"What is anonymization vs. pseudonymization?",options:["Anonymization and pseudonymization describe the exact same irreversible data transformation process applied to records","Anonymization permanently removes identifying data; pseudonymization replaces identifiers with aliases that can be re-linked","Pseudonymization is considered a categorically stronger and more complete privacy protection than anonymization techniques","Anonymization is mandatory for GDPR compliance purposes, while pseudonymization carries no legal requirement whatsoever"],answer:1,explanation:"GDPR considers anonymized data outside scope; pseudonymized data is still personal data since re-identification is possible. Pseudonymization reduces risk but doesn't eliminate privacy obligations.",optionExplanations:["Anonymization and pseudonymization are distinct processes that provide different levels of privacy protection and carry different legal implications under GDPR.","Anonymized data cannot be linked back to individuals (irreversible); pseudonymized data uses tokens or aliases but retains the ability to re-identify individuals using a separate key.","Anonymization actually provides the stronger privacy protection of the two; pseudonymization is a risk-reduction measure that still permits re-identification via a key.","GDPR requires data protection regardless of method; anonymized data exits GDPR scope entirely, while pseudonymized data remains fully subject to GDPR protections."]},
  {id:437,domain:A,question:"What is a network access control (NAC) system?",options:["A physical padlock mechanism fitted onto network switches and other physical networking equipment racks","A system that enforces policies about which devices can connect to the network, verifying compliance before access","A configuration list defining which specific network communication protocols are permitted on a given segment","A collection of ordered rules configured on a firewall that determine which traffic flows are permitted"],answer:1,explanation:"NAC (802.1X, Cisco ISE) checks device health (patching, AV, certificates) before allowing network access, quarantining non-compliant devices to a remediation VLAN.",optionExplanations:["Physical locks on equipment are physical security controls; NAC is instead a technical access control governing network connectivity based on device compliance.","NAC enforces posture assessment — checking OS patches, AV status, disk encryption, and certificates — before granting devices access to corporate network resources.","Protocol allowlists are firewall and network policy configurations; NAC is instead a device authentication and posture assessment system for endpoints.","Firewall rule sets control traffic flow between already-connected networks; NAC instead controls which devices are allowed to connect to the network at all."]},
  {id:438,domain:O,question:"What is the kill chain in cybersecurity?",options:["A specific technical technique used by defenders to forcibly terminate any running malicious process","A framework, originally from military targeting, describing stages of a cyberattack from recon to objectives","A standardized method used by investigators to properly collect and preserve digital forensic evidence","A reference list documenting the specific commands commonly issued by a particular family of malware"],answer:1,explanation:"Lockheed Martin's Cyber Kill Chain (Reconnaissance→Weaponization→Delivery→Exploitation→Installation→C2→Actions on Objectives) helps defenders understand and break attack sequences.",optionExplanations:["Stopping malware processes is an incident response action; the kill chain is instead a conceptual model describing the progression of an entire attack.","The kill chain framework breaks attacks into seven stages, allowing defenders to identify which stage they're detecting and develop controls to break the chain at each stage.","Evidence collection procedures are forensic methodology; the kill chain is instead an analytical framework for understanding the sequence of an attack.","Malware command sequences are specific threat intelligence details; the kill chain is an abstract framework applicable broadly to any type of attack."]},
  {id:439,domain:T,question:"What is a side-channel attack?",options:["An attack carried out by physically plugging directly into exposed network switch or router ports on-site","Exploiting physical traits of a cryptographic system, such as timing and power use, rather than algorithm flaws","A form of social engineering attack carried out indirectly through an unsuspecting trusted third party contact","An attack that deliberately targets an organization's backup systems rather than its primary production systems"],answer:1,explanation:"Timing attacks measure computation time to determine key bits; power analysis watches power consumption during crypto operations — these bypass mathematical security.",optionExplanations:["Physical network ports are part of standard network infrastructure; side channels instead involve physical information leakage from computing hardware itself.","Side-channel attacks extract secret keys by measuring physical characteristics during cryptographic operations — power usage fluctuates based on key bits being processed, leaking information.","Social engineering routed through a third party is a supply-chain social engineering technique; side channels instead involve physical leakage from computing hardware.","Attacking backup systems is a persistence or lateral-movement strategy; side channels are instead physical measurement attacks against cryptographic hardware."]},
  {id:440,domain:G,question:"What is the difference between authentication and authorization?",options:["Authentication and authorization are interchangeable terms describing the exact same security process","Authentication verifies identity ('who are you?'); authorization determines what that identity is permitted to do","Authorization is typically performed as the first step, occurring before any identity authentication takes place","Authentication is purely a technical mechanism, while authorization is treated as a purely non-technical policy decision"],answer:1,explanation:"Authentication proves who you are (username/password, MFA); authorization determines your access rights (can this user read this file, access this API endpoint?).",optionExplanations:["Authentication and authorization are distinct, ordered steps in access control; treating them as interchangeable leads to security design errors.","Authentication (logging in) must occur before authorization (what you can do) — you prove identity first, then the system checks your permissions.","Authentication always precedes authorization in practice — you must establish who you are before the system can determine what you're allowed to do.","Both are technical and involve policy: authentication is verified technically; authorization policies are defined by administrators and also enforced technically."]},
  {id:441,domain:T,question:"What is click fraud in the context of cybersecurity?",options:["Any general form of online fraud that is carried out by clicking on fraudulent phishing email links","Automated fraudulent clicking on pay-per-click ads using bots or compromised computers to drain rival ad budgets","A phishing technique that lures victims into clicking convincing fake buttons embedded on a webpage","A form of identity theft carried out through deceptive, fake-looking login buttons on a spoofed site"],answer:1,explanation:"Click fraud botnets generate fake ad clicks — advertisers pay for worthless clicks (competitor sabotage) or publishers generate fraudulent revenue.",optionExplanations:["Clicking fraudulent links is a phishing interaction; click fraud instead generates fraudulent clicks specifically on paid advertisements.","Click fraud uses bots to simulate user clicks on ads, costing advertisers money for traffic that never becomes customers, or generating fraudulent publisher revenue.","Fake buttons designed to steal credentials are phishing or clickjacking techniques; click fraud specifically targets digital advertising billing systems.","Identity theft through fake login forms is credential phishing; click fraud instead specifically targets advertising revenue and billing systems."]},
  {id:442,domain:A,question:"What is a deception technology platform?",options:["Marketing technology that relies on deliberately deceptive or misleading advertising claims to consumers","Security tools that deploy decoys, traps, and breadcrumbs through an environment to detect and slow attackers","Specialized technology used to automatically detect and flag deepfake video and audio content online","Simulation software used to run realistic social engineering training exercises for company employees"],answer:1,explanation:"Deception technology goes beyond honeypots — it plants fake credentials, files, and systems throughout the real environment to detect and mislead attackers.",optionExplanations:["Marketing deception is a consumer protection and ethics issue; deception technology is instead a security control that deliberately misleads attackers.","Deception platforms deploy fake users, files, network shares, and database records that look real but alert security when accessed — any interaction indicates attacker presence.","Deepfake detection addresses media authenticity problems; deception technology instead focuses on detecting and misdirecting real attackers within a network.","Social engineering training uses simulated attacks on employees; deception technology instead uses fake assets to detect real attackers operating in production."]},
  {id:443,domain:O,question:"What is a security audit?",options:["A comprehensive technical test measuring the raw processing performance of an organization's IT systems","An independent, systematic examination of security controls and policies to verify they meet requirements effectively","An automated technical vulnerability scan run periodically against an organization's network-connected systems","A periodic review of which employees currently hold specific access rights and system permissions overall"],answer:1,explanation:"Security audits provide independent verification that controls exist and work — they examine policies, test controls, interview staff, and review evidence against a standard.",optionExplanations:["Performance testing measures raw system capacity and speed; security audits instead assess whether security controls meet defined requirements.","A security audit systematically evaluates controls against a framework (ISO 27001, NIST, PCI DSS) through documentation review, testing, and interviews to provide assurance of compliance.","Vulnerability scanning is a narrow, automated technical assessment tool; auditing is a broader examination of the entire security program including governance and process.","Access rights review is a user provisioning audit exercise; a full security audit instead covers the entire security control environment, not just permissions."]},
  {id:444,domain:T,question:"What is BGP hijacking?",options:["An attacker gaining complete unauthorized administrative control over a single physical network router","Manipulating Border Gateway Protocol routing to redirect internet traffic through attacker-controlled infrastructure","An attacker breaking into and hijacking encrypted communication sessions established between two BGP routers","A fabricated attack targeting a nonexistent agency mistakenly referred to as the Border Gateway Patrol"],answer:1,explanation:"BGP hijacking announces false route information, redirecting traffic through attacker infrastructure for interception, blackholing, or traffic analysis.",optionExplanations:["Router takeover is a device-level compromise; BGP hijacking instead manipulates the routing protocol's announcements across the wider internet.","BGP (the internet's routing protocol) trusts route announcements; attackers announce more specific routes than the legitimate owner to intercept or blackhole traffic across the internet.","BGP session encryption via RPKI and BGPsec is a mitigation measure; hijacking is instead the attack on BGP's underlying route announcement trust model.","BGP stands for Border Gateway Protocol, a real routing protocol; there is no such thing as a 'Border Gateway Patrol' agency or system."]},
  {id:445,domain:G,question:"What is public key infrastructure (PKI)?",options:["A key management system that is owned, operated, and controlled exclusively by national governments only","The framework of policies, procedures, hardware, software, and roles needed to manage and revoke digital certificates","A publicly searchable online database that stores and lists everyone's encryption keys for public lookup","A dedicated system used specifically for generating, distributing, and managing employee SSH login keys"],answer:1,explanation:"PKI enables trust at scale — CAs vouch for public key ownership, browsers trust CA-signed certificates, enabling secure HTTPS worldwide.",optionExplanations:["PKI can be government-run or privately operated by commercial companies; it is not inherently a governmental system.","PKI encompasses certificate authorities (CAs), registration authorities (RAs), certificate policies, CRL/OCSP infrastructure, and key management procedures — the complete ecosystem for certificate-based trust.","Public key servers store public keys for lookup, mainly for email encryption; PKI is instead the trust hierarchy that verifies key ownership through signed certificates.","SSH key management is a separate, narrower concern; PKI uses X.509 certificates and is primarily used for TLS, code signing, and email encryption."]},
  {id:446,domain:P,question:"What is the purpose of a privacy notice?",options:["A formal warning issued to individuals specifically about the potential risks of a future data breach","A communication to individuals explaining what personal data is collected, why, and what rights they have","An internal company policy document that guides how employees should handle personal data of coworkers","A binding legal contract signed between an organization and its users governing their overall relationship"],answer:1,explanation:"Privacy notices (required by GDPR Article 13/14) must be concise, transparent, and provided at the time of data collection — they enable informed consent.",optionExplanations:["Data breach risk warnings may appear within a notice but are not its primary purpose; privacy notices instead inform about ongoing data practices.","Privacy notices (privacy policies) explain the organization's data collection practices, legal basis for processing, retention periods, data sharing, and individuals' rights — enabling informed decisions.","Internal privacy policies guide employee behavior regarding data handling; privacy notices instead communicate externally to the actual data subjects.","Privacy notices are informational documents; Terms of Service or data processing agreements are the binding contracts. Notices inform rather than create obligations."]},
  {id:447,domain:A,question:"What is the purpose of network traffic analysis (NTA)?",options:["A network engineering practice focused purely on optimizing available bandwidth allocation across links","Analyzing network flow data to detect anomalies, malicious communications, lateral movement, and data exfiltration","A workplace monitoring practice used to track employee internet usage for productivity measurement purposes","A network management practice that documents and tracks changes made to overall network topology over time"],answer:1,explanation:"NTA (using tools like Darktrace, ExtraHop, Vectra) establishes behavioral baselines and alerts on deviations — finding attackers who evade signature-based detection.",optionExplanations:["Bandwidth optimization is a network performance function; NTA instead focuses on detecting security threats hidden within traffic patterns.","NTA analyzes network flows, protocols, and behaviors to detect C2 communications, unusual data transfers, scanning activity, and lateral movement that signatures might miss.","Productivity monitoring is an HR or employee management function; NTA is instead a dedicated security detection capability applied to network traffic.","Network topology documentation is a network management housekeeping function; NTA is instead real-time behavioral analysis of traffic for security threats."]},
  {id:448,domain:O,question:"What is penetration testing methodology?",options:["An unstructured, improvised hacking attempt carried out against systems without any prior planning at all","A structured approach to simulating attacks — reconnaissance, scanning, exploitation, and reporting — to validate controls","A fully automated vulnerability scanning process that requires no manual analyst involvement whatsoever","A recurring annual compliance audit process conducted to satisfy external regulatory reporting obligations"],answer:1,explanation:"Pentest methodology (defined in PTES, OWASP, NIST 800-115) ensures comprehensive coverage, reproducibility, and actionable reporting of discovered vulnerabilities.",optionExplanations:["Unstructured hacking attempts lack documentation and defined scope; penetration testing instead follows a defined methodology with formal authorization.","Penetration testing follows structured phases: pre-engagement (scope, authorization), reconnaissance, scanning, exploitation, post-exploitation (lateral movement), and detailed reporting with remediation guidance.","Vulnerability scanning identifies potential weaknesses without exploiting them; penetration testing instead actively exploits vulnerabilities to demonstrate real impact.","Annual audits are largely compliance-driven activities; penetration testing is instead an active, hands-on simulation of attacker techniques within an authorized scope."]},
  {id:449,domain:T,question:"What is a birthday attack in cryptography?",options:["A themed attack timed to occur specifically on the anniversary date of a targeted organization's founding","Exploiting the birthday paradox to find hash collisions — inputs producing the same hash — faster than brute force","A social engineering attack that manipulates victims using their own publicly known personal birthdate details","A timing-based side-channel attack that specifically targets the cryptographic key generation process itself"],answer:1,explanation:"The birthday paradox means collision probability is much higher than intuition suggests — finding any two matching hash inputs requires only ~2^(n/2) attempts vs. 2^n.",optionExplanations:["Birthday attacks exploit mathematical probability theory, not calendar dates or actual anniversaries of any kind.","Birthday attacks exploit the statistical property that collisions (two inputs with the same hash) are found surprisingly quickly — SHA-1 had birthday attack vulnerabilities that enabled collision attacks.","Using a victim's birthdate in social engineering is an OSINT-driven pretexting tactic; birthday attacks are instead mathematical attacks on hash functions.","Timing attacks measure computation duration to leak secrets; birthday attacks instead exploit the birthday paradox specifically to find hash collisions."]},
  {id:450,domain:G,question:"What is a hardware root of trust?",options:["Implicitly trusting hardware vendors without performing any independent verification of their products at all","A hardware component (TPM, secure enclave) providing a trust foundation — verifying boot integrity and protecting keys","A physical metal key used to unlock the doors of a secured server room or data center facility on-site","Hardware equipment that carries formal certification issued by an independent, trusted certifying authority"],answer:1,explanation:"Hardware roots of trust (TPM, Intel TXT, ARM TrustZone) enable measured boot, device attestation, and secure key storage — providing trust that cannot be undermined by software.",optionExplanations:["Implicit vendor trust is a supply chain risk management concern; a hardware root of trust is instead a specific cryptographic and integrity technology.","A hardware root of trust (TPM 2.0, Apple Secure Enclave, ARM TrustZone) establishes verified system integrity from power-on, protecting keys in tamper-resistant hardware.","Physical access control keys are physical security tools for facilities; a hardware root of trust is instead a cryptographic integrity assurance technology.","Hardware certification by a trusted authority is a supply-chain verification step; a hardware root of trust is the on-device trusted component enabling secure computing."]},
  {id:451,domain:T,question:"What is a typosquatting attack?",options:["The act of unlawfully squatting or trespassing physically within a company's data center server room","Registering domain names that are common misspellings of legitimate sites to capture mistyped URLs for malicious use","Rapidly typing out malicious code by hand during development in an effort to evade static analysis","Creating and distributing fake, malicious keyboard shortcut mappings for popular operating systems"],answer:1,explanation:"Typosquatters register 'gooogle.com', 'paypa1.com', etc., capturing mistyped traffic and serving phishing pages, malware, or ads to unknowing victims.",optionExplanations:["Squatting inside a server room is a physical security concern unrelated to domains; typosquatting instead registers look-alike domain names.","Typosquatting exploits common typing errors — transpositions, added/missing letters, wrong TLDs — to capture traffic from users who mistype URLs and redirect them to malicious sites.","Typing speed during malware development has no bearing on detection evasion; typosquatting is instead entirely a domain registration strategy.","Keyboard shortcuts are legitimate OS and application features; typosquatting instead targets URL typos entered directly into browser address bars."]},
  {id:452,domain:A,question:"What is secure boot?",options:["A boot process that is protected exclusively through physical security controls guarding the server room","A firmware-level feature that verifies digital signatures of boot components before letting them run at startup","A startup sequence that requires a system administrator to manually authenticate before the machine boots up","A boot sequence in which the entire hard drive is fully encrypted before the operating system finally loads"],answer:1,explanation:"Secure Boot (UEFI feature) verifies each component in the boot chain is signed by a trusted key — preventing bootloader-level malware (bootkits) from persisting.",optionExplanations:["Physical security of the boot process is a data center control; Secure Boot is instead a firmware-level cryptographic verification of boot components.","Secure Boot uses cryptographic signatures to verify bootloader, kernel, and driver integrity before execution — ensuring no tampered or unauthorized code runs during the boot process.","Administrator authentication at boot time is a separate pre-boot authentication feature; Secure Boot instead performs automated signature verification, not human login.","Drive encryption is handled by tools like BitLocker or LUKS; Secure Boot instead verifies the integrity of boot code, not the encryption of stored data."]},
  {id:453,domain:O,question:"What is security orchestration?",options:["Restructuring and organizing the internal reporting hierarchy of an organization's security team members","Integrating and coordinating multiple security tools to work together and execute automated response workflows","Planning and conducting recurring security awareness training sessions for the general employee population","Managing the schedules, milestones, and timelines associated with ongoing security-related projects"],answer:1,explanation:"Security orchestration (in SOAR platforms) integrates SIEM, EDR, threat intelligence, ticketing, and firewalls to execute playbooks spanning multiple tools automatically.",optionExplanations:["Team hierarchy management is an organizational design decision; orchestration instead coordinates technology tools and automated workflows.","Orchestration connects disparate security tools through APIs, allowing events in one system to automatically trigger actions in others — a SIEM alert can trigger EDR isolation and firewall block simultaneously.","Security training is an awareness-building function aimed at employees; orchestration instead automates technical response workflows between tools.","Project management is a general organizational function; orchestration is instead the technical integration of security tools into automated workflows."]},
  {id:454,domain:T,question:"What is a replay attack?",options:["An attack that specifically targets a physical video or audio recording and playback device only, nothing else","Intercepting valid data transmission and maliciously retransmitting it to gain unauthorized access or repeat an action","Replaying stored audit log entries after the fact in order to reconstruct how a past attack actually occurred","An attack that involves repeating the exact same scripted lines used in a social engineering pretext session"],answer:1,explanation:"Replay attacks reuse captured authentication tokens or transactions — prevented by timestamps, nonces, and sequence numbers that make captured data invalid for retransmission.",optionExplanations:["Attacking a recording or playback device is a different, unrelated attack category; replay attacks instead target authentication or transaction data.","Replay attacks capture valid authentication packets or tokens and retransmit them later to authenticate as the original user without knowing their credentials.","Replaying audit logs for reconstruction is a forensic investigation technique; replay attacks instead attempt to gain unauthorized access through retransmission.","Repeating a social engineering script is a social engineering tactic; replay attacks are instead technical attacks that reuse captured network data."]},
  {id:455,domain:G,question:"What is the purpose of a Certificate Authority (CA)?",options:["An entity responsible for issuing and managing certificates that grant devices access to a network","A trusted entity that issues digital certificates, verifying requestor identity and binding it to a public key","A dedicated provider that generates and supplies encryption keys directly to individual end users on request","An entity responsible for issuing and tracking official licenses for commercial software products"],answer:1,explanation:"CAs form the trust hierarchy of PKI — browsers ship with trusted root CA lists; organizations can also run private CAs for internal certificate management.",optionExplanations:["Network access certificates may rely on a CA behind the scenes; the CA itself is the trust anchor that vouches for identity, not an access manager itself.","A CA validates the identity of requestors (through DV, OV, or EV verification), issues X.509 certificates binding their identity to a public key, and maintains certificate revocation lists.","CAs don't provide encryption keys directly — they bind existing public keys to verified identities, while users generate their own key pairs themselves.","Software licenses are commercial legal agreements; a CA instead issues cryptographic identity certificates used for authentication and secure communications."]},
  {id:456,domain:P,question:"What is purpose limitation in data privacy?",options:["Restricting data collection and handling to authorized staff based on job need, rather than specifying the permitted use of the data collected","Collecting personal data only for specified, explicit, legitimate purposes and not further processing it for incompatible purposes","Limiting personal data collection geographically to individuals residing within specific regulatory jurisdictions, such as EU member states, based on data residency laws","Requiring that personal data be processed only within defined retention timeframes and deleted or anonymized once those organizational or regulatory periods expire"],answer:1,explanation:"GDPR Article 5(1)(b) requires data be collected for specific purposes — using customer data collected for order fulfillment for marketing requires new consent.",optionExplanations:["Staff access restrictions implement least privilege; purpose limitation restricts the permitted uses of collected data, not which employees can access it.","Purpose limitation means the purpose for which data is collected must be stated upfront, and data cannot be repurposed for incompatible uses without new legal basis (usually consent).","Geographic limitations address data residency or cross-border transfer rules; purpose limitation concerns the intended use of data, not the location of data subjects.","Time-based restrictions are data retention periods; purpose limitation restricts the reasons data can be used, not the duration for which it may be stored."]},
  {id:457,domain:A,question:"What is a virtual private network (VPN)?",options:["A software-defined networking model that eliminates physical cables by routing all traffic through virtual switches, SDN controllers, and overlay network protocols","A technology that creates an encrypted tunnel between a client and a server, providing secure remote access and hiding internet traffic from intermediaries","A virtualized computing instance deployed within a hypervisor that is assigned a non-routable private IP address and isolated from direct external internet connectivity","An isolated internal network segment within a virtualized data center, accessible only to virtual machines sharing the same hypervisor host or virtual switch configuration"],answer:1,explanation:"VPNs encrypt traffic end-to-end (IPsec site-to-site or SSL/TLS remote access), securing communications over untrusted networks like public WiFi or the internet.",optionExplanations:["Software-defined networks virtualize network functions but still rely on physical infrastructure; VPNs use physical networks to create logical private encrypted tunnels.","A VPN encrypts traffic between endpoints, creating a private tunnel over public internet — enabling secure remote access to corporate resources and protecting against eavesdropping.","Virtual machines with private IPs are compute virtualization providing network isolation; VPNs are a networking technology creating encrypted communication tunnels between remote endpoints.","Hypervisor-internal virtual networks isolate compute workloads within a virtualization platform; VPNs extend private network access securely to remote clients over public internet."]},
  {id:458,domain:O,question:"What is a post-mortem (lessons learned) in incident response?",options:["A medical or legal forensic procedure performed by a pathologist to determine the official cause, manner, and contributing circumstances of a person's death","A structured review conducted after an incident to understand what happened, what worked, what failed, and how to improve future response","A comprehensive catalog of all systems, servers, and services that were destroyed, disabled, or permanently taken offline as a direct result of a cyberattack","A mandatory incident disclosure report submitted to law enforcement agencies documenting the cyberattack timeline, affected systems, data involved, and suspected threat actor"],answer:1,explanation:"Post-mortems identify gaps in detection, response time, communication, and playbooks — converting negative experiences into organizational security improvements.",optionExplanations:["Medical post-mortem refers to an autopsy procedure; in incident response the term is used metaphorically to describe a structured security incident retrospective review.","A post-incident review examines the timeline, what was detected and when, response effectiveness, communication flow, and identifies specific improvements to policies, tools, and training.","Documenting impacted systems is part of the incident impact assessment; post-mortem is a separate retrospective process improvement activity conducted after containment and recovery.","Law enforcement reporting may be required for certain incidents; post-mortems focus on internal lessons learned and process improvement, not external agency reporting requirements."]},
  {id:459,domain:T,question:"What is an advanced persistent threat (APT)?",options:["A recurring technical problem where a software update package repeatedly fails to install correctly, causing system instability and requiring manual IT intervention to resolve","A sophisticated, long-term attack by a well-resourced adversary (often nation-state) that maintains extended unauthorized access to achieve strategic objectives","A fully automated botnet-driven malware distribution operation that persistently deploys payloads to large numbers of unrelated victims using pre-programmed known exploits","A highly sophisticated next-generation firewall capability specifically designed to continuously absorb and deflect sustained volumetric denial-of-service attack traffic without service interruption"],answer:1,explanation:"APT groups (APT28/Fancy Bear, APT41) conduct targeted espionage, intellectual property theft, or sabotage — maintaining access for months or years while avoiding detection.",optionExplanations:["Software update installation failures are IT operations issues; APTs are sophisticated, long-term targeted attack campaigns conducted by well-funded and organized adversary groups.","APTs are characterized by advanced techniques, well-funded adversaries, long-term persistence in target networks, and specific strategic objectives — typically espionage or disruption.","Automated malware campaigns are typically opportunistic and broadly targeted; APTs are manually guided, carefully targeted intrusions against specific high-value organizations with strategic objectives.","Firewalls are defensive devices that block incoming attacks; APTs are threat actor groups conducting long-term, targeted intrusion campaigns to maintain persistent access inside organizations."]},
  {id:460,domain:G,question:"What is the principle of separation of duties?",options:["Structurally separating cybersecurity and IT operations into distinct organizational departments, each with independent management chains, budgets, and executive reporting structures","Dividing critical functions across multiple individuals so no single person can complete a sensitive task alone, reducing fraud and error risk","Deploying dedicated, isolated IT systems, applications, and data stores for each business unit to prevent cross-departmental access to sensitive information or processes","Maintaining strictly separate development, staging, and production environments with independent credentials, access controls, and change management processes to prevent unauthorized modifications"],answer:1,explanation:"Separation of duties prevents insider fraud — in finance, the person who approves payments shouldn't also be the person who processes them or reconciles accounts.",optionExplanations:["Separating security and IT organizational reporting lines can support SoD but is not its definition; SoD prevents any single individual from controlling a complete sensitive transaction.","SoD ensures fraud requires collusion between multiple people — a developer who writes code shouldn't also be able to deploy it to production, or an accountant who requests payments shouldn't approve them.","Business unit system isolation is data segregation; SoD specifically divides the steps of sensitive processes across multiple people to require collusion for fraud.","Dev/prod environment separation prevents unauthorized production changes; SoD divides job responsibilities within business processes so no single person can complete a sensitive task alone."]},
  {id:461,domain:O,question:"What is a disaster recovery plan (DRP)?",options:["A formally documented physical emergency procedure specifying evacuation routes, assembly points, floor warden assignments, and occupant accountability procedures during a fire or life-safety event","A documented strategy and procedures for recovering IT systems and data following a disruptive incident, ensuring business continuity","A step-by-step procedure for restoring accidentally or maliciously deleted files and database records from backup media using point-in-time recovery or versioning capabilities","A high-level organizational plan that addresses how a company maintains essential services, workforce functions, and customer operations throughout any type of major disruptive event"],answer:1,explanation:"DRPs specify recovery procedures, responsible parties, RTOs/RPOs, and restoration steps for specific scenarios — they must be regularly tested to be effective.",optionExplanations:["Fire evacuation plans address physical emergency egress; a DRP specifically addresses IT system and data recovery after disruptive technical or physical incidents affecting operations.","A DRP details how to restore IT infrastructure after events like ransomware, hardware failure, natural disaster, or facility loss — with specific procedures, contact lists, and recovery targets.","Accidental deletion recovery is one scenario a DRP covers; DRPs address the full spectrum of IT system recovery including ransomware, hardware failure, and facility loss.","Business continuity plans address overall operational survival including people, processes, and facilities; DRPs specifically focus on IT infrastructure and data recovery objectives and procedures."]},
  {id:462,domain:T,question:"What is a watering hole attack's key advantage over spear phishing?",options:["The attack succeeds without requiring victims to have active outbound internet connectivity, functioning entirely through redirected requests within an organization's internal network","The victim initiates the contact by visiting a known legitimate site, making it harder to train users to avoid","It reaches a broader and more diverse victim population because attackers do not need to research and individually identify each specific high-value target","It deploys more technically advanced browser exploits and zero-day vulnerabilities than the malicious links and attachments used in standard spear phishing email campaigns"],answer:1,explanation:"Watering hole attacks compromise sites victims already trust and visit regularly — unlike suspicious emails, visiting a trusted website doesn't trigger security awareness alarms.",optionExplanations:["Watering holes require internet-accessible compromised websites; the defining advantage is that victims voluntarily visit sites they trust, not that the attack bypasses internet access.","The strategic advantage is that victims come to the attacker voluntarily by visiting sites they believe are legitimate — security training teaches people to be suspicious of emails, but less suspicious of familiar websites.","Watering holes are actually more targeted than generic phishing, aimed at specific professional groups visiting known sector websites; broad reach is not the key advantage.","Both attack types can use sophisticated malware; the strategic advantage of watering holes is that victims voluntarily visit the compromised site, making user training less effective."]},
  {id:463,domain:A,question:"What is role-based access control (RBAC)?",options:["Controlling access based on an employee's role in a physical workspace","Granting access permissions based on predefined roles that align with job functions, rather than individually assigning permissions to each user","A security vetting process where users demonstrate job role competency by completing simulated authorization scenarios before they are assigned any system access permissions","An access model where individual department managers manually evaluate and approve each resource access request from their direct reports on a case-by-case basis"],answer:1,explanation:"RBAC simplifies access management — instead of configuring per-user permissions, administrators manage roles, and users inherit permissions from their assigned roles.",optionExplanations:["Physical workspace roles are physical access controls; RBAC is a digital access control model.","RBAC assigns permissions to roles (Developer, Accountant, HR Specialist) and then assigns users to roles — making access management scalable and consistent with job responsibilities.","Competency demonstrations are training assessments; RBAC assigns permissions based on defined job roles within the organization, not on performance in simulated scenarios.","Manager-controlled per-request access decisions describe a discretionary access model; RBAC is a structured, policy-driven model assigning permissions through predefined roles to all role members."]},
  {id:464,domain:P,question:"What is the difference between a privacy policy and a privacy notice?",options:["A privacy policy and privacy notice are synonymous terms that organizations use interchangeably to describe the same required disclosure document provided to all data subjects","A privacy policy is the internal governance document; a privacy notice is the external communication to individuals about how their data is used","Privacy notices serve as internal communications to employees about HR data processing, while privacy policies are external-facing documents published for customer and partner review","Privacy policies are legally binding documents enforceable by regulators, while privacy notices are voluntary transparency disclosures that organizations publish without any legal obligation"],answer:1,explanation:"Privacy policies govern internal processes; privacy notices (also called privacy statements) are the public-facing communications required by regulations like GDPR.",optionExplanations:["Privacy policies and privacy notices serve different audiences and purposes; conflating them is a common error that can result in compliance gaps under GDPR requirements.","The privacy policy guides internal practices; the privacy notice (required by GDPR Article 13) explains data practices to individuals whose data is collected.","Both apply across stakeholder groups; the key distinction is internal governance (policy guiding operations) versus external communication (notice informing data subjects of their rights).","Both have legal significance under regulations like GDPR; privacy notices are legally required under Article 13/14, while privacy policies are internal governance documents."]},
  {id:465,domain:O,question:"What is a threat intelligence feed?",options:["A social media platform or blog that aggregates cybersecurity news articles, vendor announcements, and breach disclosures for security professionals to follow and stay informed","A stream of data providing current information about threats, indicators of compromise (IoCs), threat actors, and vulnerabilities to improve defensive capabilities","An automated notification stream generated by SIEM tools, IDS sensors, and endpoint security software when suspicious events are detected within the organization's environment","A subscription service providing periodic cybersecurity alerts and advisories issued by government agencies such as CISA, FBI, or sector-specific regulatory bodies"],answer:1,explanation:"Threat intelligence feeds (AlienVault OTX, MISP, commercial feeds) provide IoCs (malicious IPs, domains, file hashes) that can be ingested into SIEM, firewalls, and EDR for automated blocking.",optionExplanations:["Cybersecurity news aggregators provide informational awareness; threat intelligence feeds are structured, machine-readable operational data used to configure security controls and detection systems.","Threat intelligence feeds deliver structured, machine-readable data (STIX/TAXII format) containing current IoCs, malware signatures, and TTP information that security tools can act on automatically.","Security monitoring alerts are outputs from your own tools detecting internal events; threat intelligence feeds are external inputs providing data about the broader threat landscape.","Government advisories are one source of threat intelligence; commercial and ISAC feeds provide higher-frequency, more granular, machine-readable technical indicators for automated security tool integration."]},
  {id:466,domain:T,question:"What is credential harvesting?",options:["Securely storing employee and service account credentials in an encrypted hardware security module or purpose-built privileged access management vault to prevent unauthorized exposure","Collecting user credentials through phishing, malware, or OSINT to use for unauthorized access","Extracting and analyzing large credential datasets from breach dumps and dark web repositories to identify patterns in password reuse across organizations and industries","Automatically generating and provisioning secure initial passwords and MFA enrollment links for new employee accounts during the IT onboarding and identity provisioning process"],answer:1,explanation:"Credential harvesters use fake login pages, keyloggers, password stealers, and breach databases to collect credentials for account takeover and lateral movement.",optionExplanations:["Storing credentials in a hardware vault is secure credential management; harvesting is the malicious act of collecting credentials from existing users for unauthorized access.","Credential harvesting collects authentication credentials through any means — fake login pages, InfoStealer malware, phishing emails, or purchasing breach data — for unauthorized access.","Analyzing breach data for research is threat intelligence work; credential harvesting is an attacker activity actively collecting credentials from victims for unauthorized system access.","Employee credential provisioning is IT identity management; credential harvesting is an attacker activity stealing authentication credentials from existing users through deceptive or malicious means."]},
  {id:467,domain:G,question:"What is the purpose of a Trusted Platform Module (TPM)?",options:["A software component providing a sandboxed execution environment for automated security testing that validates application behavior against defined security requirements and threat models","A hardware security chip that generates, stores, and manages cryptographic keys, enables secure boot, and provides device attestation","A security module that maintains and enforces an approved software vendor list, blocking installation of applications from unauthorized, unverified, or untrusted publishing organizations","A portable hardware device such as a FIDO2 security key or smart card that users carry separately and insert to authenticate their identity to systems"],answer:1,explanation:"TPM 2.0 enables BitLocker drive encryption key protection, Secure Boot, device health attestation, and is required for Windows 11 — providing hardware-anchored security.",optionExplanations:["Software testing security modules are development and QA tools; TPM is a dedicated hardware security chip providing cryptographic key generation, storage, and device attestation functions.","A TPM chip generates random numbers, stores keys in protected hardware, measures the boot process, and provides cryptographic evidence of device state — anchoring trust in hardware.","Software vendor trust lists are application whitelisting or code signing policy enforcement; TPM handles cryptographic key protection, platform integrity measurement, and hardware-rooted device attestation.","Portable authentication tokens are external MFA hardware devices; TPM is an integrated chip soldered onto the motherboard that enables platform security features within the device itself."]},
  {id:468,domain:A,question:"What is attribute-based access control (ABAC)?",options:["A file system permission model that grants read, write, or execute access to resources based on metadata attributes embedded in each individual file's properties","A flexible access control model that grants access based on attributes of the user, resource, environment, and action — enabling fine-grained, context-aware policies","An authentication mechanism that requires users to present multiple identity attributes such as username, password, and a biometric factor before access is granted","An enhanced version of role-based access control that supplements job-role assignments with additional identity verification steps before granting access to sensitive resources"],answer:1,explanation:"ABAC can express policies like 'a physician can access patient records from hospital-approved devices during working hours in clinical locations' — far more expressive than RBAC.",optionExplanations:["File system attribute-based permissions are a basic OS access control model; ABAC is a comprehensive policy-based model evaluating multiple attribute categories to make access decisions.","ABAC evaluates multiple attributes simultaneously: user attributes (role, department, clearance), resource attributes (classification, type), and environmental attributes (time, location, device) to make access decisions.","Multi-factor authentication requires multiple credential types; ABAC is an authorization model using user, resource, and environmental attributes to determine access rights after authentication.","ABAC can incorporate roles as one attribute among many, but it is a distinct and more flexible model than RBAC, not simply RBAC with extra verification steps."]},
  {id:469,domain:O,question:"What is a security gap analysis?",options:["Evaluating network throughput, latency, and bandwidth utilization against defined service-level objectives to identify capacity shortfalls that require infrastructure upgrades or optimization","A comparison of current security capabilities against desired state or industry framework requirements to identify weaknesses and prioritize improvements","Identifying unprotected pathways, misconfigured rules, or coverage gaps in firewalls, DMZ configurations, and perimeter intrusion detection systems protecting the network boundary","An evaluation of physical security controls that identifies camera coverage gaps, unmonitored entry points, and areas lacking badge readers or security guard patrol coverage"],answer:1,explanation:"Gap analyses compare current security state against frameworks (NIST CSF, ISO 27001, CIS Controls) to create prioritized roadmaps for security program improvement.",optionExplanations:["Network performance gaps are capacity planning concerns; security gap analysis assesses security program capability maturity against a framework, not network operational performance metrics.","A gap analysis maps current controls to a framework, identifies where controls are absent or insufficient, and creates a prioritized remediation roadmap based on risk and effort.","Perimeter security gap assessment is one component of a broader security gap analysis; the full process covers all security domains across the entire security program.","Physical security assessments evaluate facility controls; security gap analysis covers the entire security program including people, process, and technology controls against a comprehensive framework."]},
  {id:470,domain:T,question:"What is a drive-by download attack?",options:["Inserting a removable USB flash drive containing pre-loaded malware that automatically executes via autorun functionality when plugged into an unprotected victim computer","Malware installation that occurs automatically when a user visits a compromised or malicious website, without any user action beyond browsing","Deceiving victims into downloading and manually executing a counterfeit software update that delivers malware disguised as a legitimate application upgrade or security patch","Distributing trojanized document files or media that execute embedded malicious macros, exploit code, or payloads when the victim opens them in an application"],answer:1,explanation:"Drive-by downloads exploit browser or plugin vulnerabilities (Java, Flash, PDF reader) — simply visiting a page installs malware without clicks or downloads.",optionExplanations:["USB-based malware delivery exploits removable media autorun; drive-by downloads exploit browser vulnerabilities automatically when users visit compromised websites, requiring no physical media.","Drive-by downloads require no user interaction beyond visiting a web page — the exploit kit detects vulnerable browser components and automatically installs malware.","Fake software update attacks require user interaction to download and execute; true drive-by downloads are completely automatic, requiring no user action beyond visiting a web page.","Trojanized files that execute on open require user interaction to open; drive-by downloads install malware automatically through browser or plugin vulnerabilities without any user file interaction."]},
  {id:471,domain:G,question:"What is a key derivation function (KDF)?",options:["A cryptographic utility that takes random bytes from a hardware or software random number generator and formats them directly into fixed-length cryptographic key material","A cryptographic function that derives one or more secret keys from a master secret using a pseudorandom function, adding salt and iterations to resist brute force","A cryptographic protocol such as Diffie-Hellman or ECDH that enables two parties to independently compute a shared secret value over an untrusted public channel","A mathematical algorithm such as RSA key generation or elliptic curve cryptography that produces linked public and private key pairs for asymmetric encryption operations"],answer:1,explanation:"KDFs like PBKDF2, bcrypt, and Argon2 are deliberately slow — iteration counts make brute force infeasible even with fast hardware like GPUs.",optionExplanations:["KDFs do use randomness inputs like salt, but they derive keys from a low-entropy input secret rather than purely from random number generator output alone.","KDFs (PBKDF2, scrypt, Argon2) stretch low-entropy inputs like passwords into cryptographic keys through many rounds of hashing with salt — making each guess computationally expensive.","Key exchange protocols establish shared secrets between parties; KDFs derive one or more keys from an existing master secret using iterative hashing with salt.","Asymmetric key pair generation produces public/private keys for PKI operations; KDFs derive symmetric keys or multiple keys from a master secret or low-entropy password."]},
  {id:472,domain:P,question:"What is the privacy by default principle?",options:["Configuring systems to automatically collect and retain all available personal data attributes from users by default unless they explicitly submit an opt-out request","Configuring systems to process the minimum necessary personal data by default, requiring users to actively opt-in to share more","Configuring all privacy and data sharing settings to be visible and accessible to other users or the public by default, requiring individuals to manually restrict them","Applying privacy configuration controls automatically to newly created system default accounts while leaving administrator, service, and power user accounts outside the scope of those settings"],answer:1,explanation:"GDPR Article 25 requires privacy by default — when launching a social network, privacy should be maximum by default, not exposing profiles to everyone unless users choose to.",optionExplanations:["Maximum data collection by default is the opposite of privacy by default; the principle requires the most privacy-protective option as the starting configuration state.","Privacy by default means the most privacy-friendly option is the default choice — users shouldn't need to navigate settings to protect their privacy; that should be the starting state.","Making privacy settings public by default maximizes data exposure; privacy by default requires maximum privacy protection from the outset so users need not take action.","Privacy by default applies to all user accounts and system configurations from launch; it is not limited to default accounts or any subset of users."]},
  {id:473,domain:A,question:"What is security-as-code?",options:["Using automated static analysis code scanning tools to search application source code for known vulnerability patterns, insecure functions, and security defects before deployment","Expressing security policies, configurations, and controls as code that can be version-controlled, reviewed, tested, and automatically enforced","Writing application source code that adheres to secure coding standards, input validation practices, and cryptographic guidelines to minimize the number of exploitable software vulnerabilities","Generating security compliance reports and operational dashboards automatically using scripting and APIs that aggregate data from multiple security monitoring and logging tools"],answer:1,explanation:"Security-as-code enables policy drift detection, peer review of security configurations, and automated enforcement — bringing software engineering rigor to security operations.",optionExplanations:["Searching code for vulnerabilities is static application security testing; security-as-code specifically defines security policies, configurations, and controls as version-controlled code artifacts.","Security-as-code expresses firewall rules, IAM policies, compliance checks, and security baselines as code artifacts — enabling version control, automated testing, and consistent deployment.","Writing secure code is secure software development; security-as-code is about expressing security infrastructure configurations and enforcement policies as version-controlled code artifacts.","Automated security reporting is a useful capability; security-as-code is a broader methodology expressing the full security configuration as code for version control and automated enforcement."]},
  {id:474,domain:O,question:"What is mean time to respond (MTTR) in security operations?",options:["The average duration that customer support staff require to acknowledge, investigate, and resolve service tickets submitted through the organizational help desk system","The average time from detecting a security incident to containing it and restoring normal operations","The average elapsed time between a security researcher submitting a vulnerability disclosure report and the vendor publishing an acknowledgment or issuing a remediation patch","The average elapsed time between a vulnerability being publicly disclosed or discovered internally and the organization successfully deploying the vendor-supplied remediation patch across all affected systems"],answer:1,explanation:"MTTR measures response effectiveness — lower MTTR reduces attacker dwell time and damage. SOAR automation is a primary way to reduce MTTR.",optionExplanations:["Customer inquiry response time is a customer service metric; MTTR in security operations measures effectiveness of the security team's incident detection-to-restoration cycle.","MTTR (sometimes Mean Time to Repair) measures how quickly the security team moves from detection through containment to restoration — directly relating to attacker impact limitation.","Vulnerability report response time is a vendor disclosure metric; MTTR specifically measures the security operations team's speed from incident detection through containment and service restoration.","Patch deployment time is tracked as mean time to patch; MTTR specifically measures the full incident response cycle from initial detection through containment and normal operations restoration."]},
  {id:475,domain:T,question:"What is homograph attack (IDN homograph attack)?",options:["Crafting written content that uses English words spelled identically but carrying different meanings to obscure the intended communication from automated security content filters","Using visually similar Unicode characters to create domain names that look identical to legitimate domains, deceiving users into visiting malicious sites","Embedding concealed text or hidden data within document files using white-on-white font, invisible layers, or metadata fields to evade casual visual inspection","Exploiting weaknesses in graph-based network analysis and threat detection tools by inserting adversarial relationship data that distorts trust scoring and anomaly detection results"],answer:1,explanation:"Internationalized domain name (IDN) homograph attacks use Cyrillic 'а' instead of Latin 'a' — 'apple.com' and 'аpple.com' look identical but point to different servers.",optionExplanations:["English-language homographs are a linguistics concept; IDN homograph attacks specifically exploit Unicode character visual similarity in domain names to deceive users browsing the web.","IDN homograph attacks register domains using Unicode characters that are visually indistinguishable from common Latin characters — the Cyrillic 'а' looks identical to Latin 'a' at normal viewing distances.","Hidden text in documents is a form of data concealment; homograph attacks exploit visual similarity between Unicode domain name characters, not document content manipulation.","Graph-based tool exploitation is a different attack category; IDN homograph attacks specifically register Unicode domain names that are visually indistinguishable from legitimate Latin-character domains."]},
  {id:476,domain:G,question:"What is certificate pinning?",options:["Displaying printed copies of TLS certificates on physical bulletin boards or security notice areas so staff can manually compare and verify certificate fingerprints","Hardcoding or storing specific certificate details in an application to reject any other certificate, even from a trusted CA","An administrative practice of organizing digital certificate files into structured directory hierarchies, naming conventions, and archiving systems for certificate lifecycle management purposes","Scheduling automated calendar alerts and renewal tasks to notify certificate administrators before SSL/TLS certificate expiration dates to ensure timely certificate renewal and replacement"],answer:1,explanation:"Certificate pinning prevents MitM attacks using rogue CA-signed certificates — mobile banking apps pin their server certificate so attackers can't intercept with their own valid certificate.",optionExplanations:["Physically displaying certificates is an informal verification practice; certificate pinning is a software security technique that embeds expected certificate details directly in application code.","Certificate pinning (or public key pinning) builds expected certificate details into the application — if the presented certificate doesn't match what's expected, the connection is rejected even if it's validly signed.","File organization is an administrative task; certificate pinning is a security control embedded in application code that rejects any certificate not matching a pre-stored expected value.","Calendar-based expiration alerts support certificate lifecycle management; certificate pinning is about rejecting unexpected certificates during TLS handshakes to prevent man-in-the-middle interception."]},
  {id:477,domain:A,question:"What is east-west traffic in network security?",options:["Network traffic that originates in eastern-region data centers and is routed through backbone interconnects to servers physically located in western geographic regions of a country","Traffic flowing laterally between servers and workloads within the same data center or network segment, as opposed to north-south traffic to/from the internet","The routing paths and priority queues through which email messages traverse mail transfer agents, spam filters, and delivery servers within an organization's messaging infrastructure","Wide-area network traffic flowing between an organization's geographically distributed branch offices across MPLS circuits, SD-WAN overlays, or site-to-site VPN connections in multiple directions"],answer:1,explanation:"Most intrusion detection focuses on north-south (perimeter) traffic; attackers use east-west movement (lateral movement) to reach valuable targets inside the network.",optionExplanations:["Geographic server location is unrelated to east-west traffic; the terms describe logical traffic flow direction — lateral between internal systems versus vertical between internal and external networks.","East-west traffic flows between internal systems — server-to-server, VM-to-VM; north-south flows between internal systems and external networks. Microsegmentation controls east-west to prevent lateral movement.","Email routing is a messaging infrastructure concept; east-west traffic describes lateral data center traffic between internal servers and workloads, distinct from north-south internet-bound flows.","Branch office inter-site traffic is WAN connectivity; east-west specifically describes intra-data-center or intra-segment lateral traffic between servers and workloads within the same environment."]},
  {id:478,domain:O,question:"What is the purpose of security metrics?",options:["Demonstrating to management how much time and effort the security team expends on daily operational tasks, alert triage, and incident response activities each month","Providing quantifiable measures of security program effectiveness to support risk decisions, justify investments, and track improvement over time","Evaluating the throughput, packet loss, and latency characteristics of the network infrastructure on which security monitoring, enforcement, and logging tools are deployed","Tallying the total count of confirmed security incidents logged by the SIEM and incident management system during a defined monthly or quarterly reporting period"],answer:1,explanation:"Security metrics (patch compliance %, MTTD, vulnerability density, phishing click rates) enable data-driven security management and demonstrate value to executive leadership.",optionExplanations:["Workload reporting is an operational tracking activity; security metrics specifically measure program effectiveness, risk posture, and security control performance to inform strategic decisions.","Security metrics translate security activities into quantifiable data that executives can use to understand risk posture, allocate budget, and track progress toward security goals.","Network performance measurement is operational capacity management; security metrics specifically quantify security program effectiveness, risk levels, and control performance for security decision-making.","Incident counts are one basic security metric; a comprehensive metrics program covers vulnerability age, detection coverage, response speed, and compliance posture across the full security program."]},
  {id:479,domain:T,question:"What is a man-in-the-middle (MitM) attack?",options:["An attack requiring the adversary to physically position themselves between two communicating parties, such as between a network switch port and a workstation connection","An attack where the adversary secretly intercepts and potentially alters communications between two parties who believe they are communicating directly with each other","A social engineering technique that uses a trusted third-party intermediary to convey fraudulent instructions from an attacker to an unsuspecting target organization or individual","An attack that exploits vulnerabilities in middleware software such as message queues, API gateways, or enterprise service buses to intercept and manipulate application data flows"],answer:1,explanation:"MitM attacks (via ARP poisoning, rogue APs, SSL stripping) allow attackers to read, modify, and inject traffic — defeated by proper certificate validation and encryption.",optionExplanations:["MitM attacks can be conducted remotely over networks; physical presence is not required, as network-based techniques like ARP poisoning work without physical proximity.","A MitM attacker positions themselves in the communication path — intercepting, reading, potentially modifying, and forwarding communications between two parties who think they communicate directly.","Social engineering using intermediaries is impersonation or pretexting; MitM attacks are technical attacks that intercept and optionally modify actual network communications between two parties.","Middleware exploitation targets application infrastructure vulnerabilities; MitM attacks intercept the communication channel between two parties who believe they are communicating directly with each other."]},
  {id:480,domain:G,question:"What is the concept of least privilege?",options:["Compensating security personnel at the minimum salary level allowed by employment law or contract to reduce the organization's operating costs in the IT security department","Granting users, processes, and systems only the minimum permissions necessary to perform their intended functions, reducing the attack surface","Granting elevated administrative system permissions only during pre-scheduled maintenance windows and automatically revoking all privileged access immediately when the maintenance period concludes","Selecting and deploying the most cost-effective security tools and controls available that satisfy minimum regulatory compliance requirements while minimizing capital and operational expenditure"],answer:1,explanation:"Least privilege limits damage from compromised accounts, insider threats, and malware — a compromised standard user account can't modify system files they have no business accessing.",optionExplanations:["Salary minimization is an HR and budget management decision; least privilege is a security design principle governing the scope of access permissions granted to users and processes.","Least privilege ensures each entity has exactly the permissions needed to do its job — no more. An HR system doesn't need database admin rights; a web server process doesn't need filesystem write access.","Time-limited elevated access is just-in-time access or break-glass access; least privilege is the ongoing principle of assigning only minimal necessary permissions at all times.","Cost-optimizing security controls is budget management and procurement strategy; least privilege is a security design principle about permissions scope and is independent of financial cost."]},
  {id:481,domain:T,question:"What is adversarial machine learning?",options:["Using artificial intelligence and machine learning models to generate realistic simulations of human adversary behavior for security awareness training or automated red team exercises","Techniques to deceive, manipulate, or poison machine learning models through specially crafted inputs or training data","Training a machine learning model specifically on historical adversary attack data, threat intelligence feeds, and malware samples to improve security detection and classification accuracy","Applying machine learning and predictive analytics to analyze competitor pricing strategies, customer behavior patterns, and market trends to gain strategic business intelligence advantages"],answer:1,explanation:"Adversarial ML attacks include model poisoning (corrupting training data), evasion (inputs that fool classifiers), and model inversion (extracting training data from models).",optionExplanations:["AI-based adversary simulation is a security testing tool; adversarial ML specifically describes techniques that deceive or manipulate machine learning models through crafted inputs or poisoned data.","Adversarial machine learning attacks target AI systems — making malware evade ML-based AV by crafting inputs that the model classifies as benign, or poisoning training data to degrade model performance.","Training security ML models on attack data improves defenders; adversarial ML describes attacks against ML systems themselves, such as evasion through crafted inputs or training data poisoning.","Competitive business analytics using ML is a data science application; adversarial ML is a security domain addressing attacks that target and undermine AI and machine learning systems."]},
  {id:482,domain:A,question:"What is a privileged access workstation (PAW)?",options:["A developer workstation configured with elevated local administrator permissions and access to code repositories, build servers, and deployment pipelines for software development tasks","A hardened, isolated workstation used exclusively for administrative tasks to reduce the risk of credential theft and lateral movement","A standard corporate laptop computer on which the end user has been granted local administrator rights to install software and modify system configuration settings","A single high-security workstation shared by multiple administrators to perform privileged operational tasks, centralizing elevated-access activities to reduce hardware and licensing costs"],answer:1,explanation:"PAWs are separate from regular workstations — no internet browsing, no email, minimal software — so attackers can't steal admin credentials through phishing or drive-by downloads.",optionExplanations:["Developer workstations with elevated permissions facilitate software development workflows; PAWs are specifically hardened and isolated for administrative tasks, not general development or application usage.","A PAW is a dedicated workstation with enhanced security configurations used exclusively for privileged tasks — administrative credentials are only used from this hardened, internet-isolated device.","A laptop with admin rights lacks the isolation and hardening required; PAWs are dedicated devices used exclusively for privileged administrative tasks with no general internet use.","Shared privileged workstations undermine accountability and increase risk; PAWs must be dedicated to specific individual administrators to maintain session isolation and prevent credential cross-contamination."]},
  {id:483,domain:O,question:"What is a cybersecurity framework?",options:["A standardized rack-mount equipment system used in data centers to physically install, organize, cable, and secure network, server, and security appliance hardware components","A structured set of guidelines, best practices, and standards that organizations use to manage and reduce cybersecurity risk","A programming library or API toolkit that provides reusable security modules and abstraction layers for developers to build cybersecurity scanning, detection, or enforcement tool applications","A legally mandated set of specific cybersecurity requirements that organizations within a regulated industry are required to implement, document, and demonstrate compliance with"],answer:1,explanation:"Frameworks (NIST CSF, ISO 27001, CIS Controls) provide structured approaches to building and maturing security programs — enabling consistent risk management.",optionExplanations:["Equipment rack mounting systems are data center physical infrastructure; cybersecurity frameworks are conceptual and procedural guidance documents for managing organizational security risk programs.","A cybersecurity framework provides organized categories of security practices (Identify, Protect, Detect, Respond, Recover) that organizations use to assess current state and plan improvements.","Software development frameworks are coding libraries and platform abstractions; cybersecurity frameworks like NIST CSF are program management guidance for organizational security risk management.","Frameworks are often voluntary guidance rather than mandates; regulations like HIPAA and PCI DSS mandate specific requirements, while frameworks like NIST CSF provide flexible adoptable guidance."]},
  {id:484,domain:T,question:"What is a polymorphic malware?",options:["Malware designed to conduct coordinated simultaneous attacks against multiple different target organizations or network segments within the same large-scale deployment campaign","Malware that constantly changes its code signature while maintaining its functionality to evade signature-based detection","Malware that combines multiple distinct attack techniques such as phishing delivery, browser exploitation, and credential theft to compromise targets through several simultaneous vectors","Malware whose source code has been compiled and packaged into executable versions written in several different programming languages to maximize compatibility across target platforms"],answer:1,explanation:"Polymorphic malware mutates with each infection (using encryption with variable keys, code rearrangement) — its signature never appears twice, defeating traditional antivirus.",optionExplanations:["Multi-target attack campaigns describe attack breadth; polymorphic behavior specifically refers to the mutation of malware code signatures to evade signature-based antivirus detection.","Polymorphic malware uses mutation engines to alter its binary signature with each copy while keeping its malicious functionality — making signature-based detection ineffective against new instances.","Multi-vector attacks describe attack diversity and delivery methods; polymorphism specifically describes the automated code signature mutation that occurs to evade antivirus detection engines.","Multi-language malware implementation is a development characteristic for cross-platform compatibility; polymorphism specifically describes automated signature mutation during propagation to evade detection."]},
  {id:485,domain:G,question:"What is a nonce in cryptography?",options:["A placeholder or filler value inserted into cryptographic protocol message fields that carries no functional significance and can be any arbitrary number without affecting security","A number used once — a random or sequential value that ensures cryptographic operations produce unique results and prevents replay attacks","A configurable initialization parameter passed to a cryptographic hash function that controls internal state setup, output digest length, or the computational work factor of hashing","A computational technique that applies a password hash function repeatedly through thousands of iterations to increase the computational cost of brute-force attacks against stored credentials"],answer:1,explanation:"Nonces in TLS handshakes, TOTP tokens, and challenge-response authentication ensure each session or operation is unique — preventing attackers from reusing captured values.",optionExplanations:["Nonces are not meaningless fillers; they serve the critical cryptographic purpose of ensuring uniqueness in operations and preventing replay attacks by adversaries capturing session data.","A nonce (number used once) ensures that even identical plaintexts produce different ciphertexts, and that captured challenge values cannot be reused by attackers.","Hash function configuration parameters control algorithm behavior; nonces are single-use random or sequential values that ensure cryptographic operations produce unique outputs and prevent replay attacks.","Iterative hashing for work factor increase is key stretching; nonces are single-use random or sequential values that ensure uniqueness in cryptographic operations across sessions."]},
  {id:486,domain:P,question:"What is the purpose of a data protection officer (DPO)?",options:["A role responsible for protecting the organization's proprietary business data, trade secrets, and intellectual property from competitive intelligence gathering and corporate espionage activities","An independent role required by GDPR for certain organizations, responsible for overseeing data protection compliance and serving as the point of contact with supervisory authorities","An IT operations role responsible for designing, scheduling, testing, and validating data backup procedures to ensure recovery time and recovery point objectives can be met","A specialized incident response investigator focused on examining confirmed data breaches, conducting forensic analysis, and determining the scope and root cause of unauthorized data access"],answer:1,explanation:"GDPR Article 37 requires DPOs for public authorities and organizations with large-scale personal data processing — they advise, monitor compliance, and liaise with data protection authorities.",optionExplanations:["Protecting data assets from competitors is a business intelligence and IP protection function; DPOs focus on personal data protection compliance and data subject rights under GDPR.","A DPO provides expert advice on data protection obligations, monitors compliance with GDPR, conducts DPIAs, and serves as the liaison with the supervisory authority (national data protection authority).","Data backup and recovery is an IT operations function; the DPO is a compliance oversight and advisory role that serves as the liaison with supervisory authorities.","Breach investigation may involve the DPO in a coordination capacity; the primary DPO role is ongoing compliance monitoring, advisory, and supervisory authority liaison, not forensic investigation."]},
  {id:487,domain:A,question:"What is network topology and why does it matter for security?",options:["The visual representation of network infrastructure using standardized icons, symbols, and line styles in diagramming tools to document the environment for administrators and architects","The arrangement of network elements and how they interconnect, which determines data flow paths, potential attack paths, and where security controls should be placed","The physical arrangement of network cables, conduits, patch panels, and structured wiring connecting network devices within a building or campus communications infrastructure","The physical organization and mounting arrangement of servers, switches, routers, and security appliances within standard equipment racks in a data center or network closet"],answer:1,explanation:"Security controls must be placed where they can inspect all relevant traffic — topology determines if a firewall actually sees traffic or if there are paths around it.",optionExplanations:["Network diagrams represent topology visually; topology itself is the actual physical and logical structure of connections and data flows that the diagram is meant to depict.","Network topology (bus, star, ring, mesh, tree) determines which systems can communicate directly, where traffic flows can be monitored, and where security controls must be deployed.","Physical cabling is one component of topology but captures only the physical layer; full network topology includes logical elements like VLANs, routing domains, and virtual overlay networks.","Rack organization is data center physical layout management; network topology describes logical interconnections, data flow paths, and the placement of controls regardless of physical arrangement."]},
  {id:488,domain:O,question:"What is continuous security monitoring (CSM)?",options:["Employing physical security guards working in rotating shifts around the clock to monitor server rooms, data centers, and network closets for unauthorized physical access","Ongoing, automated collection and analysis of security data to provide real-time visibility into organizational security posture and enable rapid threat detection","Scheduled monthly reviews of security system configurations, policy settings, access log summaries, and control effectiveness metrics conducted by the security operations or compliance team","Regularly scheduled authorized simulated attacks performed by security professionals to test and measure the effectiveness of technical defenses and the detection capabilities of the team"],answer:1,explanation:"CSM (NIST SP 800-137) implements automation to continuously collect metrics, perform change detection, and report security status — replacing periodic point-in-time assessments.",optionExplanations:["Security guards provide physical monitoring of facilities; CSM refers to automated technical monitoring of IT security controls, system configurations, network traffic, and security events.","CSM uses automated tools to continuously monitor network traffic, system configurations, user behavior, and security controls — providing ongoing visibility rather than periodic snapshots.","Monthly reviews are periodic point-in-time assessments; CSM is continuous and automated, providing near-real-time security status rather than periodic snapshots of security posture.","Penetration testing is periodic adversarial simulation producing point-in-time findings; CSM is continuous automated monitoring of security posture and control effectiveness over time."]},
  {id:489,domain:T,question:"What is an injection attack?",options:["Physically inserting hardware implants, modified storage media, or tampered firmware modules into computing systems to introduce malicious code directly at the hardware supply chain level","A class of attacks where malicious code or data is inserted into an interpreter (SQL, OS, LDAP, XML) as part of a command or query","Inserting crafted forged network packets into an existing TCP or UDP session to hijack connections or inject unauthorized commands between two communicating network systems","Using specialized post-exploitation frameworks to load and execute malicious shellcode or modules directly into the memory address space of a running process on a compromised system"],answer:1,explanation:"Injection attacks (SQL, command, LDAP, XPath, XML) exploit interpreters that incorrectly process untrusted data as executable code — prevented by parameterized queries and input validation.",optionExplanations:["Physical hardware attacks are supply chain or hardware tampering; injection attacks exploit software interpreters through application input, not physical access to hardware components.","Injection attacks exploit the boundary between data and code — when an interpreter processes attacker-supplied data as commands. SQL injection inserts SQL; command injection inserts OS commands.","Network packet injection manipulates network-layer communication streams; application injection attacks target the interpreters processing application-layer input such as SQL engines or OS command shells.","Process memory code injection is a post-exploitation technique for privilege escalation or evasion; injection attacks specifically target input interpreters processing attacker-supplied data as executable commands."]},
  {id:490,domain:G,question:"What is a security policy hierarchy?",options:["Organizing the information security department personnel into a tiered management structure ranked by each staff member's years of experience, technical certifications, and seniority","A layered structure of security documents with policies at the top (high-level), supported by standards, then procedures, then guidelines","A prioritized catalog of security controls ranked by their measured effectiveness, implementation cost, and risk reduction value relative to the organization's current threat profile","A defined escalation path specifying which security analysts, team leads, managers, and executives must be notified at each severity level during an active security incident"],answer:1,explanation:"Policies state what must be done; standards specify how; procedures give step-by-step instructions; guidelines offer best practice recommendations — each level provides increasing detail.",optionExplanations:["Personnel seniority hierarchy is organizational HR structure; security policy hierarchy is a documentation governance framework organizing policies, standards, procedures, and guidelines by authority level.","The policy hierarchy (Policy → Standard → Procedure → Guideline) provides different levels of specificity and binding authority — policies are mandatory; guidelines are advisory.","Security control prioritization is risk management and investment planning; the policy hierarchy organizes security documentation by binding authority and specificity, not control effectiveness or cost.","Escalation chains are incident response communication procedures; the security policy hierarchy organizes governance documentation from high-level mandatory policies down through specific advisory guidelines."]},
  {id:491,domain:T,question:"What is domain generation algorithm (DGA) malware?",options:["Malware that automatically registers large volumes of newly created domain names with legitimate registrars to use as distribution infrastructure for spam email or phishing campaigns","Malware that generates large numbers of domain names algorithmically for C2 communications, making it difficult to block by domain blocklist","Malware that routes all command-and-control traffic through trusted, legitimate cloud services and social media platforms to evade domain reputation filtering and network monitoring","A legitimate network administration utility used by IT teams to generate and resolve test domain names for DNS infrastructure load testing and service performance measurement"],answer:1,explanation:"DGA malware (Conficker, GameOver Zeus) generates hundreds of daily domains — defenders must sink-hole all possible domains while attackers only need to register one that isn't blocked.",optionExplanations:["Domain registration for spam uses static or bulk-registered domains; DGA malware generates pseudorandom domain names algorithmically so only the botmaster needs to register one from the list.","DGA-based malware and its C2 server use the same algorithm with the same seed to generate the same list of domains daily — the botmaster only needs to register one domain from the list for contact.","Using legitimate domains for C2 is domain fronting or dead drop resolvers; DGA malware specifically generates large numbers of pseudorandom domain names, not routing through legitimate services.","Network testing tools generate domains for operational purposes; DGA is a malware technique generating thousands of pseudorandom domains for resilient C2 infrastructure that evades blocklists."]},
  {id:492,domain:A,question:"What is a bastion host?",options:["A physically reinforced secure facility or vault constructed specifically to house server and network infrastructure with heavy blast protection, restricted entry, and armed security","A hardened, exposed server that sits on the network boundary, providing a single, secure entry point into a protected network","A centralized application server deployed within the DMZ to host all organizational security software including SIEM, vulnerability scanners, and endpoint detection management consoles","A secondary standby server maintained in hot or warm state to automatically take over processing responsibilities if a primary critical system fails or becomes unavailable"],answer:1,explanation:"Bastion hosts have minimal software, enhanced logging, strict access controls, and serve as the only authorized path into a secured network zone — like a jump server for administrative access.",optionExplanations:["Fortified data center facilities are secure physical infrastructure; a bastion host is a network-facing hardened server, not a building, that provides controlled entry to a protected network.","A bastion host is deliberately exposed to the internet but stripped down to only essential services with maximum hardening — all access to internal networks must pass through it for logging and control.","Centralized security application servers host security tooling; bastion hosts are hardened entry-point servers, not application servers, providing strictly controlled and logged network boundary access.","Failover standby servers provide high availability and redundancy; bastion hosts provide controlled and audited entry points to protected network segments, not redundancy for other systems."]},
  {id:493,domain:O,question:"What is a cyber threat intelligence (CTI) program?",options:["A formal organizational program for submitting detailed cybercrime reports, including technical indicators and attribution evidence, to FBI, CISA, or other law enforcement agencies","An organized function that collects, analyzes, and produces actionable intelligence about threat actors, their capabilities, and intentions to support defensive decisions","A structured repository of historical security incident records containing timelines, affected systems, attacker techniques, and remediation steps taken by the organization over time","A structured application security technique used during software design to systematically identify potential threats, attack surfaces, and mitigations for applications under development"],answer:1,explanation:"CTI programs analyze strategic intelligence (who is targeting us, why), operational intelligence (current campaigns), and tactical intelligence (IoCs, TTPs) to improve defenses.",optionExplanations:["Law enforcement reporting is an incident response obligation; CTI is an intelligence production function focused on generating actionable analysis of threats to support proactive defensive decisions.","CTI collects data from threat feeds, dark web monitoring, incident analysis, and OSINT, then produces intelligence that informs detection rules, defensive priorities, and risk assessment.","Incident databases are historical operational records; CTI produces forward-looking, analyzed intelligence about current and emerging threat actors, capabilities, and intentions to inform defenses.","Threat modeling is a software security design technique; CTI is an ongoing intelligence production program focused on external threat actor tracking, not application design security analysis."]},
  {id:494,domain:P,question:"What is a legitimate interest basis for processing personal data under GDPR?",options:["Any documented organizational justification, whether operational, financial, or strategic, that a controller provides to explain why it collects and processes personal data from individuals","A legal basis (GDPR Article 6(1)(f)) allowing processing when the controller's legitimate interests outweigh individual privacy interests, after conducting a three-part test","A legal principle stating that any data processing conducted primarily for a commercial or profit-generating purpose is automatically lawful under all applicable data protection regulations","A legal basis under GDPR Article 6(1)(e) that permits public authorities and government agencies to process citizen data when necessary to perform public interest tasks"],answer:1,explanation:"Legitimate interest requires: purpose test (is the interest legitimate?), necessity test (is processing needed?), and balancing test (do legitimate interests override individual rights?).",optionExplanations:["Not every business reason qualifies; legitimate interest under GDPR Article 6(1)(f) must pass a three-part test establishing the interest, necessity, and balance against individual rights.","Legitimate interest is one of six GDPR legal bases — it requires documenting the interest, demonstrating necessity, and balancing it against individuals' rights and reasonable expectations.","Commercial purposes do not automatically confer lawfulness; legitimate interest must be specifically assessed through the three-part test and documented in a legitimate interests assessment.","Public task is the Article 6(1)(e) basis for government processing; legitimate interest under Article 6(1)(f) is a separate basis applicable primarily to private sector controllers."]},
  {id:495,domain:G,question:"What is quantum cryptography and how does it differ from quantum-resistant cryptography?",options:["Quantum cryptography and quantum-resistant cryptography are interchangeable terms that both describe encryption approaches using quantum mechanical principles to secure data transmissions","Quantum cryptography uses quantum physics principles (QKD) for provably secure key exchange; quantum-resistant cryptography uses classical mathematical algorithms designed to resist quantum computer attacks","Quantum key distribution remains entirely theoretical with no practical implementations, while quantum-resistant algorithms are currently standardized by NIST and deployed in production environments","Post-quantum cryptographic algorithms require access to quantum computers to execute their mathematical computations, while quantum key distribution can operate on classical network hardware"],answer:1,explanation:"QKD (quantum key distribution) physically detects eavesdropping; post-quantum cryptography (CRYSTALS-Kyber, CRYSTALS-Dilithium) uses math problems quantum computers can't efficiently solve.",optionExplanations:["Quantum cryptography and quantum-resistant cryptography address fundamentally different problems; confusing them is a common error, as one uses quantum physics while the other avoids quantum threats.","Quantum cryptography (QKD) uses quantum mechanics to distribute keys — any eavesdropping disturbs quantum states and is detectable. Quantum-resistant (post-quantum) algorithms are classical math designed to be hard for quantum computers.","QKD is commercially deployed by vendors like ID Quantique and Toshiba; both approaches are real technologies, not theoretical, though quantum-resistant algorithms are more broadly accessible.","Quantum-resistant algorithms run entirely on classical computers and are designed to be safe even when adversaries have quantum computers; QKD uses quantum hardware for key distribution."]},
  {id:496,domain:T,question:"What is a ransomware-as-a-service (RaaS) model?",options:["A commercially licensed cloud-based platform provided to cybersecurity researchers and incident responders for safely detonating and analyzing ransomware samples in controlled isolated environments","A criminal business model where ransomware developers provide their tools and infrastructure to affiliates who conduct attacks and share the ransom proceeds","A commercial professional service offered by incident response firms to help organizations decrypt files, restore systems, and recover operations after suffering a ransomware attack","A classified government signals intelligence program that covertly monitors ransomware group communications and infrastructure to gather attribution data and disrupt operations before attacks occur"],answer:1,explanation:"RaaS (LockBit, BlackCat/ALPHV) lowers the barrier to ransomware attacks — affiliates don't need to develop malware, only conduct attacks — explaining the explosion of ransomware groups.",optionExplanations:["Legitimate ransomware analysis sandboxes help defenders study threats; RaaS is a criminal commercial model where ransomware developers sell tools and infrastructure to criminal affiliate attackers.","RaaS operates like legitimate SaaS — developers provide ransomware, infrastructure, and support; affiliates conduct attacks and receive 70-80% of ransom payments; developers receive the rest.","Ransomware recovery services help victims respond to incidents; RaaS is the criminal distribution model that enables affiliates to conduct ransomware attacks using pre-built criminal infrastructure.","Government cyber operations to disrupt ransomware exist but are law enforcement functions; RaaS is a criminal commercial service model enabling non-technical affiliates to conduct ransomware campaigns."]},
  {id:497,domain:A,question:"What is mutual authentication?",options:["Multiple end users simultaneously submitting login requests to the same application or system through concurrent parallel authentication sessions at exactly the same moment","A process where both parties in a communication session verify each other's identity, not just the server verifying the client","An access control mechanism requiring that two or more designated administrators must independently review, approve, and countersign before any privileged administrative operation is permitted","An authentication process where a user must provide different credential types in sequence, with each credential type verified and accepted before the next credential prompt appears"],answer:1,explanation:"Mutual TLS (mTLS) has both client and server present certificates — API security commonly requires mTLS to ensure only authorized systems can call APIs, not just anyone with credentials.",optionExplanations:["Simultaneous multi-user logins are concurrent session management; mutual authentication requires both communicating parties to verify each other's identity, not simultaneous logins by different users.","Mutual authentication prevents rogue servers — in standard HTTPS, only the server is authenticated; mTLS requires clients to also present certificates, enabling server-side client verification.","Dual-administrator approval is a form of separation of duties; mutual authentication is a protocol-level process where both parties in a communication session verify each other's identity.","Sequential multi-step credential entry describes step-up authentication or MFA; mutual authentication is bidirectional — both the client and server verify each other's identity during session establishment."]},
  {id:498,domain:O,question:"What is the NIST Cybersecurity Framework (CSF) core structure?",options:["Plan, Do, Check, Act — the four-stage continuous improvement cycle used in ISO 27001 information security management systems and quality management standard implementations","Identify, Protect, Detect, Respond, Recover — five functions organizing cybersecurity activities into a cohesive lifecycle","Prepare, Prevent, Detect, Contain, Eradicate — five phases commonly referenced in incident response and digital forensics methodology for systematically managing cybersecurity incidents","Govern, Identify, Protect, Detect, Respond, Recover — six functions introduced in the updated NIST Cybersecurity Framework version 2.0 published by NIST in February 2024"],answer:1,explanation:"NIST CSF 1.1's five functions provide a common language for cybersecurity risk management — CSF 2.0 adds Govern as a sixth function encompassing cybersecurity governance.",optionExplanations:["Plan-Do-Check-Act is the PDCA cycle used in ISO 27001 and ISO 9001 management systems; NIST CSF organizes cybersecurity activities into five distinct functions across a security lifecycle.","NIST CSF (version 1.1) organizes activities into Identify (asset management, risk assessment), Protect (access control, training), Detect (monitoring), Respond (response planning), and Recover (recovery planning).","Prepare-Prevent-Detect-Contain-Eradicate resembles incident response lifecycle phases; NIST CSF is a broader security program management framework, not a sequence of incident response steps.","Govern-Identify-Protect-Detect-Respond-Recover is the correct NIST CSF 2.0 structure; the original version 1.1 has five functions without the Govern function, which is what this question tests."]},
  {id:499,domain:T,question:"What is a trojanized software update?",options:["A poorly optimized software update that introduces performance regressions, increases resource consumption, or causes system slowdowns on devices after it is successfully applied","Legitimate software updates that have been compromised to deliver malware, exploiting users' trust in official update mechanisms","A software update package that requests excessive operating system permissions or resource privileges beyond what the application's stated functionality legitimately requires to operate","A mandatory software update automatically pushed to managed devices by vendor or MDM systems that users cannot decline, defer, or reschedule at their own convenience"],answer:1,explanation:"SolarWinds, Asus Live Update, and NotPetya (disguised as M.E.Doc accounting software) are examples of trojanized updates that compromise thousands of targets simultaneously.",optionExplanations:["Performance-degrading updates are quality defects or intentional design decisions; trojanized updates are specifically legitimate update packages compromised to deliver malware to trusting recipients.","Trojanized updates compromise the update distribution chain — developers, build systems, or update servers — so that legitimate users downloading and installing valid updates receive malware.","Excessive permission requests may indicate malicious behavior, but they are a static analysis indicator; trojanized updates specifically compromise the update distribution chain to deliver malware.","Forced automatic updates are a deployment policy mechanism; trojanized updates are specifically compromised legitimate update packages used to deliver malware through trusted update mechanisms."]},
  {id:500,domain:G,question:"What is the CIA triad?",options:["A classified security model developed by the Central Intelligence Agency defining operational compartmentalization protocols to protect sensitive intelligence sources and methods from exposure","Confidentiality, Integrity, and Availability — the three core principles guiding information security that all security controls aim to protect","A set of operational security practices and counterintelligence protocols used by the Central Intelligence Agency to protect classified programs, personnel, and agent identities","A three-level hierarchical information classification framework designating government information as Confidential, Secret, or Top Secret based on the damage that disclosure would cause"],answer:1,explanation:"Every security control maps to CIA: encryption preserves Confidentiality, checksums verify Integrity, redundancy ensures Availability — these three properties define information security.",optionExplanations:["CIA as an intelligence agency has its own security models; in information security, CIA is an acronym for Confidentiality, Integrity, and Availability — the three core security objectives.","The CIA triad defines information security objectives: Confidentiality (only authorized users access data), Integrity (data is accurate and unmodified), and Availability (systems and data are accessible when needed).","CIA operational security practices are intelligence community protocols; the CIA triad is an information security framework defining the three fundamental security properties all controls must protect.","Government information classification tiers use Confidential, Secret, and Top Secret levels; the CIA triad defines security properties — Confidentiality, Integrity, and Availability — not classification levels."]},
  {id:501,domain:O,question:"What is application whitelisting?",options:["A governance process in which an organization's IT or security team evaluates and approves specific web-based SaaS applications before employees are permitted to use them","A security control that allows only explicitly approved applications to run on a system, blocking all unauthorized software including malware","A curated procurement list of pre-vetted software vendors and publishers that have passed security review and are approved for organizational software purchasing decisions","A mail gateway security control that inspects inbound email attachments and blocks or quarantines messages containing file extensions associated with executable or script content"],answer:1,explanation:"Application whitelisting (Windows AppLocker, WDAC) is one of the most effective controls against malware — if malware isn't on the allowed list, it cannot execute regardless of how it arrives.",optionExplanations:["Web application approval is a governance and shadow IT control process; application whitelisting is a technical endpoint control preventing unauthorized executables from running on systems.","Application whitelisting maintains a list of approved executables, and the OS enforces that only listed applications can run — blocking all unknown software including zero-day malware.","Approved vendor lists are procurement governance tools; application whitelisting is a technical enforcement control on endpoints specifying exactly which executable files are permitted to run.","Email attachment filtering is a mail security gateway control; application whitelisting controls which executables can run on endpoint systems, preventing malware execution regardless of delivery method."]},
  {id:502,domain:T,question:"What is a business email compromise (BEC) attack?",options:["Gaining unauthorized access to an organization's email server infrastructure by exploiting application vulnerabilities, weak credentials, or misconfigured email authentication protocols","A sophisticated social engineering attack using impersonated or compromised business email accounts to authorize fraudulent financial transfers or data theft","Sending unsolicited bulk commercial email at high volume using a company's legitimate email domain to distribute advertising content, malware, or fraudulent messages to recipients","Delivering malicious executable files, macro-enabled documents, or archive files embedded with malware through targeted email attachments to compromise the recipient's endpoint systems"],answer:1,explanation:"BEC attacks (costing billions annually) impersonate executives (CEO fraud) or vendors, manipulating employees into wire transfers or payroll redirections.",optionExplanations:["Email server compromise may be a step in BEC but is not its definition; BEC is the social engineering fraud committed using impersonated or compromised business email accounts.","BEC attacks typically impersonate executives ('urgent wire transfer needed'), business partners, or legal counsel to convince employees to bypass normal financial controls.","Bulk spam using business domains is domain abuse; BEC is targeted fraud aimed at specific individuals in a company to authorize financial transfers, not broad-audience email spam.","Malware email delivery is phishing; BEC typically avoids malware and instead exploits human trust through impersonation and social engineering to authorize unauthorized financial transactions."]},
  {id:503,domain:A,question:"What is a demilitarized zone (DMZ) in the context of industrial control systems (ICS)?",options:["A physical buffer territory established between two hostile nation states or military forces under a ceasefire or armistice agreement to prevent direct armed confrontation","A network segment between corporate IT networks and operational technology (OT) networks that controls and monitors data flows between them","A network zone that has been intentionally left without security controls or traffic monitoring to allow unrestricted bidirectional communication between all connected devices and systems","An isolated staging environment used by industrial control engineers to safely test, validate, and configure new ICS software and hardware before deploying to production systems"],answer:1,explanation:"ICS DMZs prevent direct connectivity between business IT and critical OT networks — a jump server in the DMZ provides controlled, monitored access to OT systems.",optionExplanations:["Geographic military buffer zones are international security concepts; an ICS DMZ is a network security architecture segment isolating industrial control systems from corporate IT networks.","An OT/IT DMZ enforces data diode or firewall-controlled flows between corporate networks and industrial control systems, preventing IT security incidents from directly impacting OT operations.","DMZs have precisely defined security controls; they are the enforcement point between network segments, not a security-free zone, providing controlled and monitored data flow between OT and IT.","Testing environments validate changes before deployment; an ICS DMZ is a permanent production security architecture segment controlling and monitoring data flows between IT and OT networks."]},
  {id:504,domain:P,question:"What is cross-border data transfer regulation under GDPR?",options:["Postal and logistics regulations governing the physical transportation of paper records, printed documents, and storage media across international borders between countries","Restrictions on transferring personal data to countries outside the EU/EEA that don't provide adequate privacy protection, requiring safeguards like standard contractual clauses","Trade and customs regulations that apply to the import, export, and cross-border shipment of electronic equipment, computers, and networking hardware between countries","Technical and legal standards governing the physical connectivity and peering arrangements of international undersea cable systems, internet exchange points, and cross-border network links"],answer:1,explanation:"GDPR Chapter V restricts transfers to non-adequate countries — organizations use SCCs (Standard Contractual Clauses), BCRs, or adequacy decisions to enable lawful transfers.",optionExplanations:["Physical document transportation regulations are postal and customs law; GDPR cross-border rules govern electronic transfers of personal data to countries without adequate privacy protection.","GDPR prevents personal data from being sent to countries without equivalent protection — transfers require adequacy decisions (like UK, Japan), SCCs, BCRs, or other GDPR-approved mechanisms.","Device customs regulations are trade and import law; GDPR transfer restrictions are data protection legal requirements governing where personal data about EU residents may be processed.","Network interconnection standards are telecommunications infrastructure regulations; GDPR transfer restrictions are data protection legal requirements applied to personal data, not to network physical connectivity."]},
];
